const ALL_POSTS = [{"phase": "phase1", "type": "おはよう", "text": "おはようーー🌸💗\n\n最近ね、仕事とレッスンの両立が\n想像以上にハードで🥺💦\n\n心が折れそうになるけど、\nみんながそばで見ててくれてるからがんばれる🥺💗\n\n今日も笑顔でがんばるぞーー💪💗\n応援しててね🥺🌸\n\nいってきます✨", "date": "2026-04-15", "views": 452, "likes": 47, "replies": 37}, {"phase": "phase2", "type": "ダンス", "text": "ただいま〜💖\nレッスンお休みだからお家で自主練してた💕\n\nこういう日ってちょっと気抜いちゃいそうになるけど、\n逆に自分と向き合える時間でもあるなって思ってる～✨\n\n歌はこの前うまく出なかったところを中心に、\n何回も同じフレーズ繰り返してみた✨\n\nダンスも動画見ながら細かい動き確認して、\n自分のできてないところをちゃんと見直せた気がする！！！\n\nでもこうしてる間に他の子たちも、練習してるんだろうなって思うと負けてられない💦💦\n\n今日もまだまだ頑張らないとだ！！！\n\nふれふれーー！って応援してくれたら嬉しいな💖", "date": "2026-04-12", "views": 420, "likes": 43, "replies": 29}, {"phase": "phase2", "type": "オーディション", "text": "今日は1日ほんとうにねむかった💦💦\n\n最近ね、布団入ってから考え事しちゃって\nなかなか眠れない日が続いてるの🥲💭\n\nレッスンのこととか、オーディションのこととか\n「あそこもっとできたかも」とか\n「このままで大丈夫かな」って\n頭の中でずっと繰り返しちゃって\n気づいたら時間だけどんどん過ぎてて💦\n\n昼間は大丈夫だけど、\n夜になるといろいろ不安になっちゃう。\n\n今日はちゃんと眠れたらいいなあ、、、。\n\nかのんのことぎゅーーーって優しく抱きしめてほしい🥺💖", "date": "2026-04-11", "views": 580, "likes": 43, "replies": 26}, {"phase": "phase2", "type": "ダンス", "text": "ただいま〜💖\n今日ね、ダンスレッスンで新しい振りの話が出て\nアクロバット入れることになったの🥺💦\n\n最初聞いたとき「え、ほんとにやるの…？」\nってちょっとびっくりしちゃったんだけど\nかのんね、実は昔ちょっとだけ体操やってたことあって🤭\n\nだから完全に初めてではないんだけど、\n久しぶりすぎて体が思うように動かなかった😂\n\n今日は軽く動き確認しただけなのに、\nタイミングとか高さとか全然安定しなくて\n「できてたはずなのに…！」って\nちょっと悔しくなった🥲\n\nオーディションでも見せられたらいいよねって話になってせっかくならちゃんと形にして、\n自分の強みとして出せるようにしたいなって思ってるの💓\n\n歌もダンスもまだまだだけど、\nそこにプラスして“これできるよ”っていうものがあると\n少しでも印象に残れるかなって思ってて🥺\n\nだから今は、基礎からもう一回ちゃんと確認して\n怖さなくせるように練習していくつもり💪💖\n\n(怪我もすごくよくなったし、\n気をつけてやればぜったい大丈夫だから安心してね🥺 🥺 )", "date": "2026-04-10", "views": 420, "likes": 38, "replies": 22}, {"phase": "phase2", "type": "オーディション", "text": "ただいま〜💖\n元メンバーの子から久しぶりに連絡きて、\n嬉しい報告が🤭 🤭\n\nその子も再デビューに向けて頑張ってるって聞いて\nなんかそれだけで、すごく安心したの🥲💖\n\n少し昔のことも話して、\n今はそれぞれ違う場所にいるけど、\nあの頃、一緒にレッスンしてた時間とか\nステージ立ってたときのこととかも少し思い出して\n懐かしい気持ちにもなったんだよね。\n\n「今何してるのかな、、、」\nってその子のこと考えちゃうこともあったから\n元気に頑張ってるって知れてすごくほっとしたの。\n\nもしかしたらいつかオーディションで会うかもしれないから\nその時はライバルとして一緒に頑張っていけたらいいな🥺💖", "date": "2026-04-09", "views": 427, "likes": 43, "replies": 26}, {"phase": "phase2", "type": "ダンス", "text": "ただいま〜💖\n新卒の女の子がお昼休みに話しかけてくれて\n「先輩ってすごく美人ですよね✨」\nって言われてすっごくうれしくてニヤニヤしちゃった🤭\n\n「前は何してたんですか？」\nって聞かれたけど、\nアイドルしてたとは言えなくて、そっけない回答になっちゃった💦\n\n再デビューの準備をしてること、\nまだここ以外には言ってないけど、\nもしデビューできたらちゃんと言いたい💖\n\nだからダンスも歌もすっごく上手になって\nみんなをびっくりさせたいんだ🙈\n\nよし！！！明日もがんばるぞーーー✨", "date": "2026-04-08", "views": 464, "likes": 38, "replies": 26}, {"phase": "phase2", "type": "ボーカル", "text": "ただいま〜💖\nボーカルレッスン終わったんだけどね、\n今日はちょっと苦戦しちゃった🥲\n\n高音のところでどうしても声が引っかかって、\n「もう一回いこうか」って言われて\n同じフレーズを何度も繰り返してたの。\n\n昔声が出なくなったときのこと、思い出しちゃって\nあのときみたいに出なかったらどうしようって\n一瞬よぎっちゃった。\n\nうまくいかない瞬間があると、不安になるんだよね🥺\n\nでもね、\n一回深呼吸して、\n「今は今」って切り替えてからもう一回出してみたの。\n\nそしたらさっきより少しだけ\n力抜いて出せた気がして、安心した🥺\n\nまだ不安がゼロになったわけじゃないけど、\nそれでもちゃんと前に進めてるって思いたい。\n\nでもこうして前向きな気持ちになれるのも\nいつも応援してくれてるみんなのおかげだよ。\n\n改めて本当にありがとう✨\n\n明日もがんばるね🥺 🥺", "date": "2026-04-07", "views": 436, "likes": 40, "replies": 28}, {"phase": "phase2", "type": "ダンス", "text": "ただいま〜💖\nダンスレッスン終わったよ🥲💦\n\n今日ね、振り入れの続きやってたんだけど\n 細かい動きが全然ついていけなくて大変だった💦\n\n同じとこ何回もやり直しになって、\n すごく先生に申し訳ない気持ちと、\n「なんでこんなにできないの」\nって自分が嫌いになりそうだった。\n\n「そこ遅れてる！」「もう一回！」って\n何度も止められて、\n頭では分かってるのに体が追いつかない感じでちょっと悔しかったの🥺\n\n明日もがんばれるかな。。。", "date": "2026-04-06", "views": 557, "likes": 42, "replies": 37}, {"phase": "phase2", "type": "ボーカル", "text": "レッスン終わったよ〜💖\n今日はボーカルだったんだけどね、\nちょっとだけうまくいかなくて🥲💭\n\n声は出てるのに、\n自分の中で「なんか違う」って感じがずっとあって\n何回も同じフレーズ歌い直してたの🎤💦\n\n先生にも「もう少し力抜いていいよ」って言われたんだけどそれが逆に難しくてちゃんとやろうとするほど\nうまくいかなくなる🥺\n\nでもね、最後の方に一回だけすっと声が出た瞬間があって「あ、今のかも」って思えたの。\n\nほんの一瞬だったけど、\nああいう感覚忘れたくないなって思ったし\nまだちゃんと歌えるようになりたいって\n改めて思ったの💭💖\n\n昔諦めかけたこともあったけど、\nやっぱり歌うの好きなんだなって思う🩷\n\nねえ、もしステージに立てたら\nそのときはちゃんと見に来てくれる？🥺💖", "date": "2026-04-01", "views": 561, "likes": 37, "replies": 25}, {"phase": "phase2", "type": "ダンス", "text": "ただいま〜💖\nダンスレッスン終わりで床に座り込んじゃってる🥲💭\n\n振り入れが思ってたより早くて、\n頭では分かってるのに体がついていかないから悔しくて💦💦😢\n\n周りのみんなはどんどん進んでいくし、\n置いていかれてる感じがして\n正直ちょっと焦る💦\n\nでもね、先生に\n「表情すごくいいよ」って言ってもらえて\nあ、ちゃんと見てくれてるんだって思ったら\n少しだけ救われた気がした🥲💖\n\nまだ全然足りないし、\nもっとできるようになりたいって思うけど\nそれでもこうやって一歩ずつ進めてること、\nちゃんと大事にしたいなって思ったの。\n\n早く上手になって、\n応援してくれてるみんなに、ちゃんと応えられる自分になりたいって思ってる💭🥺\n\nこれからも、こんなかのんだけど、\nちゃんと見ててくれる？🥺💖", "date": "2026-04-01", "views": 598, "likes": 42, "replies": 33}, {"phase": "phase4", "type": "質問", "text": "みんなに聞きたい💖\n春といえばこれ！って曲ある？\nかのんはね、春になると決まって聴きたくなる曲があって、\n通勤中に桜が見えた瞬間とか、窓開けたら風が気持ちよかった時とか、なんか自然と手が伸びてしまう感じがいいんだ～～💓🌸\n\nみんなの春ソング、リプで教えてほしいな✨\n新しい曲に出会えるかもしれないから、楽しみにしてる🙈💕", "date": "2026-03-31", "views": 630, "likes": 41, "replies": 28}, {"phase": "phase2", "type": "ボーカル", "text": "ただいま💖\n今日のボーカルレッスン、なんかいつもより手応えがあって、帰り道ずっとテンション上がってた🥺💕\n\nレッスンの後半にね、先生から「得意な曲も練習していいよ」って言ってもらえて。好きなYOASBIをたくさんうたっちゃった💖\n\n先生に「感情の乗せ方が上手くなってる」って言ってもらえた時、じーーーんってきてしまった😭💕\n\n最近ラップとか苦手なことばかり練習してて、「かのんって本当に向いてるのかな」って思う日もあったから、得意なものを褒めてもらえた瞬間に一気に報われた気がした💖\n\nしんどい練習が続いても、こういう瞬間があるから諦めたくないんだよね💪\n早くちゃんとしたステージで、バラードを歌いたいな🥺\nその日のためにまた明日も頑張る💕\n\nもっと上手くなってみんなにも早く聴かせたいな🙈", "date": "2026-03-30", "views": 578, "likes": 44, "replies": 35}, {"phase": "phase2", "type": "ダンス", "text": "ただいま💖\n今日のダンスレッスン、ちょっときつくてへとへとだあーーー🥺💦\n\n新しい振り付けに入ったんだけど、頭では「こう動くんだ」ってわかってるのに、\n体が全然ついてこなくて。\n\n先生に「リズムの取り方がずれてる」って言われるたびに、「どこがずれてるんだろ」ってなって30回くらいやりなおした💦\n\nでもね、何回か繰り返してたら「あ、こういうことか」ってなる瞬間があって。体に染み込んでいく感覚が、しんどいけど好きなんだよね🥺\n\n「まだまだだな」って思う反面、「でも今日より明日の方が絶対うまくなる」って思えてて。そういう積み重ねを信じてやるしかないんだよね💪\n\nオーディションまでに間に合うかな、って不安になる日もあるけど、コツコツ自分を信じてがんばる🥺\n\n心折れないで夢を追いかけられるのも、いつも応援してくれてるみんなのおかげだよ🙈💕\n本当にありがとう✨", "date": "2026-03-29", "views": 639, "likes": 40, "replies": 29}, {"phase": "phase1", "type": "日常", "text": "ねね！みんなのＸの名前だけど、それにした理由がしりたい💖\nいつもリプしながら、気になってたんだあーー🙈\n\n本名？っぽい人もいれば、アニメのキャラクターとかあだ名っぽい人もいて\n個性が出てて面白いなあっておもうんだよね💖\n\nかのんも名前変えちゃおうかな？💓🤭", "date": "2026-03-28", "views": 1793, "likes": 44, "replies": 33}, {"phase": "phase4", "type": "デート", "text": "帰り道に夜桜発見🩷\nいつかお花見デートいきたいな🥺\n\nおすすめの場所あったらおしえて🙈 https://t.co/LSkyrMX0P4", "date": "2026-03-27", "views": 872, "likes": 48, "replies": 35}, {"phase": "phase2", "type": "ダンス", "text": "さっきダンスしてたらターンの時に思いきりこけて恥ずかしかった💦\n\n怪我はしてないから安心してね💦\n\n今日は仕事で会場の設営とか力仕事多かったから、体力があんまりなくてちょっとふらふらしてる💦\n\nみんなのぎゅーーーでエネルギーチャージしたいな🥺 🥺", "date": "2026-03-26", "views": 633, "likes": 45, "replies": 34}, {"phase": "phase2", "type": "レッスン", "text": "アイドルとしてステージに立つっていう夢は変わらないんだけど、それ以上に「誰かにとっての希望になりたい」っていう気持ちが最近どんどん強くなってきてて🥺\n\nしんどい夜に「かのんの曲を聴いたらまた頑張れた」って思ってもらえたり、「かのんがいてくれてよかった」って思ってもらえたり、そういう存在になりたいの💪\n\nかのんも実際辛い時にすくわれたことがあって、そのアイドルみたいになれたらいいなっておもうの🥺 \n\n誰かの「また頑張ろう」の理由になれることってすっごく素敵なことだと思うんだ💕\n\nはぁ、、、もっとがんばらないとなあーー！！\nこれからレッスン行ってくるね✨", "date": "2026-03-25", "views": 626, "likes": 44, "replies": 28}, {"phase": "phase2", "type": "オーディション", "text": "かのんの理想のデートはね、、、\n遊園地とか映画とか、もちろん楽しいんだけど、何気ない日常をたのしみたい✨\n\n例えばね、休日の朝にふたりでスーパー行って、「今日何食べたい？」ってやりとりしながら食材選んで、一緒に料理して、「これ美味しいね」「次はこれ作ってみたい」とか、そういう会話がしたいんだ💕\n\n帰り道にコンビニ寄って、アイス選んで、「それ一口ちょうだい」ってなるやつもちょっと憧れる💖\n\n特別じゃない時間を一緒に過ごせる人がいたら、それだけで幸せだなって思って🥺\n\nオーディションとかレッスンとか、気をはることが多いから、そういう時間があったらいいなって思っちゃった💖\n\nみんなはかのんとどんなデートしたい？🙈", "date": "2026-03-24", "views": 1709, "likes": 45, "replies": 35}, {"phase": "phase2", "type": "ダンス", "text": "まだ先の話だけど、大手事務所のオーディションがあるの、、、‼️\n\nまずはそこに受からないといけなくて今練習がんばってるんだ💕\n\nそこで勝つために自分の武器を作らないといけないんだけど、\n「かのんは何が得意なんだろう？」って考えたらどんどん自信がなくなってつらい。。。かのんは良い意味でダンスも歌もそこそこなんだよね、、、、。\n\nでもそこからぐっと伸ばすのってほんとうに大変で💦💦\n\n日中はお仕事だから練習時間がほんとーーに足りなくて焦ってる💦\n\n奨学金とかレッスン費の返済もあるから仕事はぜったい休めないし、両立がむずかしい😂 😂 \n\nかのんがあと2人ほしいくらいだよーーー💦\nそしたらもっとみんなとお話したりデートいけたりするのにな🥺 \n(夢のなかでは実践中だよ🤭 )", "date": "2026-03-23", "views": 729, "likes": 53, "replies": 29}, {"phase": "phase4", "type": "デート", "text": "すっごくラーメン食べたいきぶんだけど、ダイエットしないといけないから今日はやめておこうかな😂 😂 \n\nみんなとデートいけるまでの楽しみにとっておこうっと🤭", "date": "2026-03-22", "views": 663, "likes": 49, "replies": 32}, {"phase": "phase2", "type": "ダンス", "text": "ダンスのレッスンおわったよ💖\n先生に「前より全然よくなってる」って言ってもらえて、すっごくうれしかった💓\n\n今まで何度やっても「もう一回！」ってなってたところが、今日初めて「そう、その感じ！」ってなって笑😂 \nその瞬間、なんか涙出そうになっちゃった🥺\n\n上手くなってるって実感できる瞬間って、どんなにしんどい練習も「これのためだった」って思えて。\n\nレッスン前は「今日だけ休もうかな」って正直思ってたのに、来てよかったって毎回なるんだよね笑😂🥺\n\nしんどいことが続いても、こういう瞬間があるから諦めたくないって思える。\nみんなが応援してくれてるから頑張れてるって、今日も改めて思ったよ🥺\nほんとありがとう🥺", "date": "2026-03-21", "views": 675, "likes": 40, "replies": 26}, {"phase": "phase1", "type": "日常", "text": "今日も花粉がやばかった😂💦\n\nマスクしてても鼻がムズムズするし、目が開けてられないし、通勤中ずっとくしゃみしてた笑💦\n\nでもね、電車降りて歩いてたら桜のつぼみが膨らんでるのを見つけて、ちょっとだけ気持ちが上がってしまった🌸\n\n花粉はやばいけど、春は好きなんだよね💖\n(桜見たら許せた笑)\nみんなは花粉大丈夫？🥺 \n花粉症の人、一緒に乗り越えようね笑💪", "date": "2026-03-20", "views": 779, "likes": 44, "replies": 27}, {"phase": "phase3", "type": "気持ち", "text": "はぁ、、、。ちょっと落ち込んでる。\n\n資料の数字が一部違ってて、大反省、、、。\n\n「なんでこうなったの」って詰められて、うまく言葉が出なくてずっと泣きそうだった。\n\n 「すみません」って言うしかなくて、でもそれだけじゃ全然足りなくて、帰り道ずっと引きずってたんだ。\n\nこれからレッスン行くのに正直気持ちが切り替わらないよ。。。。", "date": "2026-03-19", "views": 803, "likes": 48, "replies": 36}, {"phase": "phase2", "type": "ボーカル", "text": "ボーカルレッスン終わった✨\n\n今日は発声をいつもよりしっかりやったんだけど、最初なかなか声出なくてちょっと焦った💦\n\nでも途中からだんだん声が出てきて、最後に歌ったときは少しだけ楽に出せた気がする🩷\n\n先生にも「高いところ前より安定してきたね」って言ってもらえて、ちょっと嬉しかった☺️\n\nまだまだ課題いっぱいだけど、こうやって少しずつ変わっていくの感じると頑張ろうって思える💪\n\n歌うのってやっぱり楽しいなって改めて思ったレッスンだったなあーー！！\n\n明日もがんばるぞーー🩷\nおやすみなさい💤", "date": "2026-03-17", "views": 664, "likes": 44, "replies": 29}, {"phase": "phase2", "type": "ダンス", "text": "今日ね、ダンスのレッスンが終わったんだけど、すごく嬉しいことがあって報告させて🥺✨\n\nずっと苦戦してたターンが、やっとできるようになったの💓\n\n先生に「そう、そのバランス！」って言われて、\n思わず「やった！」って声が出ちゃった😂\n\nバラード担当だったかのんは、激しいダンスがすごく苦手で、特にターンは軸がブレブレで、何度も転びそうになってたんだよね💦\n\nでも今日、やっと体の使い方が掴めて、3回連続で成功したの🙈\n\nまだまだ完璧じゃないけど、「少しずつ前に進んでる」って実感できて、すごく嬉しかった🥺\n\nあの子に見せたい姿に、一歩ずつ近づいてる気がする🌸\n\nみんなが応援してくれるから、頑張れるんだよね💕\n\n本当にありがとう😭\n\n明日もレッスンあるけど、今日の感覚忘れないように頑張るね💪", "date": "2026-03-16", "views": 675, "likes": 47, "replies": 37}, {"phase": "phase2", "type": "ダンス", "text": "この前フォロワーさんに「かのんって普段どんなお仕事してるの？」って聞いてもらったので、答えるねー💓\n\nかのんは今、化粧品の会社で企画のお仕事をしてるよ💄✨\n\n新しいコスメのアイデアを出したり、「こんな商品あったらいいよね」っていうコンセプトを考えたり、パッケージのデザインを考えたりするお仕事なんだあーー‼️\n\nまだまだ勉強中で、先輩たちに教えてもらうことも多いんだけど、コスメがもともと好きだから「こういう商品かわいいかも！」って考える時間はやっぱり楽しい✨\n\nあとね、これはちょっとした夢なんだけど、いつかアイドルの舞台メイクとかで使えるコスメを考えてみたいなって思ってる✨\n\nステージのライトってすごく強いし、汗もかくし、普通のメイクだと崩れやすかったりするの💦\n\nだから「ライブでも映えるコスメ」とか、「踊っても落ちにくいリップ」とか、そういうの作れたら素敵だなって思うんだよね✨\n\nあとはアイドルグループとコラボしたコスメの開発とかにも携われたらいいなあ、、、なんて考えてるんだ💕\n\nダンスや歌のレッスンしてると、メイクの大変さも実感することあるから、いつかその経験も活かせたらいいなって思ってる✨\n\nまだまだ先の夢だけど、仕事もアイドルになる夢も両方あきらめたくない💖\n\n今は大変かもしれないけど、どっちも叶えるまでがんばるんだ💪🩷\n\nでももし両方叶ったらその時はどっちを両立しようか悩んじゃうなぁ💦笑", "date": "2026-03-15", "views": 1571, "likes": 50, "replies": 36}, {"phase": "phase2", "type": "ダンス", "text": "ただいまーー❤️レッスン終わったよ〜🥺💦\n\n今日はね、振り付けの細かい部分を徹底的に練習したんだけどやっと先生から「いいね、その表情！」って言ってもらえたの✨\n\nダンスって、技術だけじゃなくて表情も大事なんだよね🌸\n\nバラード担当だった時は、優しい表情で歌うことが多かったけど、\n\n今練習してる曲は、もっと強くてかっこいい表情が求められるから、最初は全然できなくて悔しかった😢\n\n鏡の前で何度も何度も練習して、\n\n「こういう感じかな？」って試行錯誤してたんだけど、今日やっと掴めた気がする🥺\n\nアイドル時代の経験が活きてるなって思う瞬間もあって、「ああ、あの時の経験、無駄じゃなかったんだ」って感じた💓\n\nレッスン終わった後、先生に「最近、成長してるね」って言われて、嬉しくて泣きそうになった😭\n\nみんなの応援があるから、こうして頑張れてるんだよ✨\n本当にありがとう💕\n\n明日も全力で頑張るね💪\n\nおやすみなさい🐰", "date": "2026-03-14", "views": 715, "likes": 43, "replies": 38}, {"phase": "phase1", "type": "おはよう", "text": "おはよう💓\n体調良くなって、今日からレッスン行けそうだーー！！\n\nずっとベッドで寝たきりだったから体力が落ちちゃった💦\n\n今日はジムでランニングからはじめないとだあーーー💦\n\n休んだ分早く取り戻さないとって焦ってる💦\n\nレッスン無事おわったら報告するね✨\nいってきます💓", "date": "2026-03-14", "views": 721, "likes": 46, "replies": 38}, {"phase": "phase1", "type": "おはよう", "text": "おはよーー！！\nたくさん寝たらかなり良くなったよ💖\n\nみんなのリプ見てたらかのんのそばで優しく看病してくれてるきぶんになって元気でたよ🥺 \n\nほんとうにありがとう✨\n\n早くレッスンいきたいな🥺😭", "date": "2026-03-13", "views": 869, "likes": 45, "replies": 32}, {"phase": "phase3", "type": "体調", "text": "おはよう！\nみんな心配かけちゃってごめんね、、、\n\n病院で薬もらったんだけど、だいぶ効いてきたよ🥺 \n\nまだ安静にしないといけないから今日もゆっくり休むね💦\n\nリプ返すのおそくなってごめんね。", "date": "2026-03-12", "views": 756, "likes": 49, "replies": 37}, {"phase": "phase1", "type": "日常", "text": "熱でちゃった💦💦\n頭すっごくいたくてぼーーっとするあ、、、", "date": "2026-03-11", "views": 774, "likes": 50, "replies": 46}, {"phase": "phase2", "type": "ダンス", "text": "だだいま🩷\nダンスレッスン終わった✨\n\n今日は振り入れの続きだったんだけど、思ってたより難しくて途中ちょっと頭こんがらがってた💦\n\n先生が「もう一回最初からやってみよう」って言ってくれて、何回も繰り返してやっと少し体に入ってきたよーー🩷\n\nダンスってその場ではできた気になっても、次の動き入ると急に分からなくなることあるの、、💦\n\nでも今日のレッスンは最後の通しでちょっとだけ形になった気がして嬉しかった☺️\n\n汗いっぱいかいたし、体もくたくただけど、やっぱり踊るの楽しいなって思った日だった🩷\n\nまだまだ覚えることたくさんあるけど、次のレッスンまでにちゃんと復習しておきたい✨\n\n明日も頑張るぞーー‼️", "date": "2026-03-10", "views": 629, "likes": 52, "replies": 35}, {"phase": "phase2", "type": "レッスン", "text": "仕事おわったーー😮‍💨💦\n今日もなかなかしんどかったな〜笑\n\n立ちっぱなしで足がもう限界なんだけぢ、ここからレッスン行くんだよね💦\n\nでもね、「かのんならできる」とか 「応援してるよ」とか見てたらなんか急にめちゃくちゃ元気になっちゃった笑\n\nよし、レッスン行ってくるね〜！！🔥\n今日もがんばるぞーーー✨", "date": "2026-03-09", "views": 725, "likes": 46, "replies": 38}, {"phase": "phase2", "type": "ボーカル", "text": "おつかれさま🩷\n今日はボーカルレッスンだったんだ✨\n\n先生に「もっと感情を乗せて」って 何度も何度も言われて、途中でめちゃくちゃ悔しくなった😭💦\n\n「声に気持ちを乗せるってむずかしいなあーーー💦」って ずっと考えながら歌ってた💭\n\nでもね、レッスンの最後の最後に一回だけ 先生が「今のよかったよ」って言ってくれて🥺\nもう、その一言でぜんぶ吹き飛んだ笑\n\nかのんまだまだ全然なんだけど、 絶対うまくなってみせるって決めてる💪🔥\n\nいつかみんなに聞いてもらって、「上手だね🩷」って言ってもらいたいんだあーーー‼️\n\nちょっと今日は疲れちゃったからお風呂に入って寝るね🩷みんなが夢に出てきたらいいな🌸", "date": "2026-03-08", "views": 767, "likes": 59, "replies": 42}, {"phase": "phase1", "type": "日常", "text": "あ、、、、、やん🙈🙈", "date": "2026-03-07", "views": 824, "likes": 54, "replies": 30}, {"phase": "phase2", "type": "ダンス", "text": "おはよーー🌸\n昨日リプ見ながらソファで寝落ちしちゃった💦🥺\n\nまだ返せてなくてごめんね😭\n一つ一つ読んですっごくしあわせな気分だったよ🌸🩷\n\n今日はね、昨日ダンスのレッスンちょっと無理しちゃったから、お休みするんだーー🥲🥲\n\nみんなは今日何してる？❤️\nお仕事の人はかのんがたくさん応援するね🩷", "date": "2026-03-07", "views": 747, "likes": 49, "replies": 35}, {"phase": "phase2", "type": "ダンス", "text": "おつかれさま🩷\nレッスン行ってきたよ〜💃✨\n\n今日はね、基本のステップの確認から始まって、姿勢とか体の使い方を細かく見てもらったの。\n\n同じ動きでも、腕の角度とか重心の置き方で全然見え方が変わるって教えてもらって、「なるほど〜！」って思うことばっかりだった🙈💭\n\nあとね、振り付けの一部分も練習したんだけど、まだ体がついてこなくて何回もやり直し…😂\n\nでも先生が「今すごく良くなってるよ」って言ってくれて、ちょっとだけ自信ついたんだあーーー‼️✨\n\nまだまだ練習中だし、完璧にはほど遠いんだけど、少しずつできることが増えていくのが楽しいなって思えてるよ💓\n\n今度ファミリーのみんなには特別に、レッスン中のかのんの写真をプレゼントしようかなって思ってる🤍\n\nちょっと恥ずかしいけど、今がんばってるかのんも見てもらえたらうれしいな🥺💓\n\n受け取ってくれるかな、、、？💓", "date": "2026-03-06", "views": 669, "likes": 46, "replies": 27}, {"phase": "phase2", "type": "ダンス", "text": "おつかれさま🩷\n\n今日ね、ずっとできなかったダンスの振り付けがはじめてうまくできたんだあーーー‼️✨\n\nなんか急に体が動いて自分でもびっくりして笑っちゃった笑\n\nちょっと前まで、鏡の中の自分を見るのが\n正直しんどかったんだよね😔💦\n\n「向いてないのかな」って何度も思った💦\n\nそれでも諦めなかったのはさ、アイドルになりたいって気持ちと、みんながいてくれるからだと思う🫶💕\n\n努力ってちゃんと積み重なってたんだなあって\n体で感じた一日だったよ🌸\n\nかのん、ちょっとだけ前に進めた気がする💪🔥\n\n今日も一日おつかれさまでした💌\nみんなが夢に出てきたらいいな🌙", "date": "2026-03-05", "views": 754, "likes": 49, "replies": 40}, {"phase": "phase3", "type": "感謝", "text": "みんな聞いて〜💦💦\n\nかのんの偽物のアカウントが出没したから注意してね💦\n(既に気づいてくれて教えてくれたみんなありがとう😭)\n\nみんなを騙そうとするなんて許せない😭\n大切なみんなを守りたいから、ちゃんと伝えておきたかったの🥺\n\nもしまたこういうアカウントが出たら教えてくれたらうれしいな🥺 https://t.co/QK8ju8SHYV", "date": "2026-03-04", "views": 905, "likes": 51, "replies": 33}, {"phase": "phase1", "type": "おはよう", "text": "おはよ〜🌸\n\n今日もお仕事だあーー💦\n\n朝からバタバタだけど、昨日の夜、みんなからのリプ読んでたら、\n「今日も頑張ろう」って思えたよ🩷\n\n最近みんながふぁみりーに入ってくれてから前より絆が強くなった気がする🌸🤭\n\nかのんもみんなにたくさんパワーーをおくるね✨🙈\n(え⭕️え⭕️パワーはあっちでね🤭)\n\nみんなとこうして繋がれてること、\nすごく幸せだなって思ってる😭\n\n今日もレッスンで帰りは遅くなりそう💦💦\n\n今日も一緒に頑張ろうね💪", "date": "2026-03-04", "views": 847, "likes": 53, "replies": 47}, {"phase": "phase2", "type": "ダンス", "text": "【ご報告💕】\n\n怪我のことだけど、ちょっと状態が良くなってきたの🥺✨\n\n心配かけてごめんね💦\n\nここ数日、無理しないように気をつけてて、レッスンも先生と相談しながら調整してたんだけど、\n\n今日、久しぶりに痛みが少ない状態で踊れたんだ😭\n\nまだ完全に治ったわけじゃないから油断は禁物だけど、\n「あ、良くなってきてる」って実感できてうれしかったんだあーー💓\n\nみんなが「無理しないでね」「お大事にね」って、何度も何度も言ってくれたから、ちゃんと休むことができたんだと思う🥺\n\n本当にありがとう😢\n\nこれからも焦らず、ゆっくり治していくね✨\n\nまた全力でダンスレッスンできる日が近づいてる気がして、すごくワクワクしてる🙈🙈\n\n早く完治させて、みんなに「なおったよーー‼️」って報告したい🌸\n\n引き続き、無理はしないように気をつけるね💕\n\n明日もレッスンがんばるぞーー🫶", "date": "2026-03-03", "views": 868, "likes": 48, "replies": 40}, {"phase": "phase1", "type": "おはよう", "text": "おはよ〜🌸\n\n昨日の夜、みんなからのリプ読んでたら、夜中の2時になってた😂💦\n\n一つ一つのリプ、何度も読み返しちゃって、「こんなに想ってくれてるんだ」って思ったら、涙が出そうになったんだよね😭\n\nみんなの優しい言葉、応援してくれる言葉、ぜーーんぶ、かのんの宝物だよ🩷🌸\n\nちょっと眠いけど、心はすっごく満たされてるきぶん✨\n\nみんなのおかげで、頑張れそうだあーーー‼️💪\n\n今日はレッスンがあるから返信遅れちゃうかもだけどちゃんと見てるからね🙈🩷\n\n今日もいちにち一緒に頑張ろうね🥺\n\n行ってきます💕ぎゅーーー🫶", "date": "2026-03-03", "views": 853, "likes": 57, "replies": 47}, {"phase": "phase2", "type": "ラップ", "text": "おつかれさま🩷\n仕事とレッスンでバタバタの1日だったあーーー😭💦\n\n今日は仕事が立て込んでて、お昼休憩もほとんど取れなくて、終わったらオンラインだけどレッスンに直行したんだよね💦\n\nラップの練習、今日も何度も何度も同じフレーズを繰り返して、先生に「もう一回！」って言われるたびに、\n心が折れそうになった😢\n\n「今日も疲れたな、、、」ってぼーっとしてたんだけど、\nみんなからのリプ読んですっごく元気出た🩷\n\nやっぱり愛の力って偉大だね✨\nうれしいのと同時にちょっとえ⭕️なきぶんになったから🦪をいじじしちゃった🤭\n\nファミリーのみんなはもう見てくれたかな？🩷\n\n仕事で疲れてても、レッスンで心が折れそうになっても、みんながそばにいてくれるから、\n「また明日も頑張ろう」って思えるんだよね✨\n\nかのんね、一人だったら、きっとここまで頑張れなかったと思う🥺\n\nあっ！もしよかったら、かのんのえ⭕️なひと夏の体験談の感想をLINEかリプでくれたらすっごくうれしいな🩷\n(最後まで読んでくれたよね？🤭)\n\nがんばって書いたから聞きたくなったの🙈\n\n今日は幸せなきぶんで眠れそうだな🩷", "date": "2026-03-02", "views": 876, "likes": 50, "replies": 36}, {"phase": "phase3", "type": "note", "text": "今ね、note書きながら、同期だったあの子のこと思い出して、ずっと泣いてた😭\n\nその子が、突然亡くなってから、ずっと考えてることがあるんだ。\n\n「なんで、あの子だったんだろう」って🥺\n\nあの子は、かのんよりずっと前向きで、ずっと輝いてて、ずっと人を笑顔にできる子だった。\n\nなのに、なんであの子が先に、、、。\n\n神様って不公平だよね。\n\n「かのんが代わりになればよかったのに」って、何度も思った。\n\n声を失って、夢も希望もなかったかのんより、あの子の方が、ずっと生きる価値があったんじゃないかって。\n\nでもね、もしかして、これは神様が与えた「試練」だったのかもしれないって。\n\n「かのんはアイドルとしてずっと輝いてほしい！！私、かのんの歌声、大好きだから。」\n\nその言葉の重みを、本当の意味で理解するための試練だったんじゃないかって🥺\n\n昨日まで笑ってた人が、今日にはいなくなることもある。\n「また明日ね」って言った言葉が、最後の言葉になることもある。\n\nそれを、身をもって知ったんだ。\n\nだからこそ、今を全力で生きなきゃいけないんだよね。\n\n「いつか」じゃなくて、「今」。\n「そのうち」じゃなくて、「今日」。\n\n夢があるなら、今追いかけなきゃいけないし、\n伝えたい想いがあるなら、今伝えなきゃいけないって思う。\n\n辛いけど、その痛みがあるから、今のかのんがいるんだよね。\n\n「あの子の分まで生きなきゃ」って思えるから、頑張れる。\n「あの子が見てる」って思えるから、諦めずにいられる。\n\nあとね思うのは、「生きてる限り、夢を追いかけられる」っていう希望があるんだなってこと。\n\nだからね、ステージに立って、「かのんは今アイドルしてるよ」って、あの子に報告したいんだ🌸\n\n今伝えたいこと、今やりたいこと、今感じたいこと。\n全部、全部、後回しにしないで、今全力でやることが、あの子もきっと喜ぶんだと思う。\n\nあの子が教えてくれた「命の儚さ」と「今の尊さ」。\n\nそれを胸に、これからも前に進んでいきたい🥺\n\nあとね、もし再デビューしたら絶対に叶えたいことがあるんだ！\n\nそれを今書いてるところ🤭\n\n早くみんなに読んでもらいたいな🙈\n\n完成したら教えるね〜！！\n重い話しちゃってごめんね、、、、\n\n長くなっちゃたけど読んでくれてありがとう🥺\nぎゅーーーー🩷", "date": "2026-02-23", "views": 1088, "likes": 63, "replies": 42}, {"phase": "phase3", "type": "note", "text": "おはよう🌸昨日寝落ちしちゃてリプ返せてなくてごめんね😭\n\n昨日少し考えてたんだけど、てこのアカウント始めてもう1か月たつの🥺早くない！？？\n\n最初はめちゃくちゃ不安で、本当に続けられるのかなって思ってたんだよね。。。(こんなにたくさんの人が見てくれるなんて夢にも思わなかった💦)\n\nでもみんなが温かく迎えてくれて、毎日優しい言葉かけてくれて、気づいたら ここが大切な居場所になってたよ🥺\n\n嬉しいこともあったし、仕事とかレッスンとかで辛いこともあったけど、\nいつもそばにみんながいてくれたから、かのんは頑張れたんだと思う💕\n\nみんなにたくさんの優しさをもらって、本当に嬉しい気持ちでいっぱいだよ///\n\nこれからもっと深く繋がりたいなって思ってるんだけど、\nその前に「本当のかのん」を知ってほしいなって🌸\n\nまだね、話せてないことがたくさんあるの。\n全部話さなくてもいい。そう思う人もたくさんいると思う。\n\nでもね、かのんはこれからはそんなかのんも含めて好きって言ってくれる人ともっと仲良くなりたいんだ🥹\n\nだからね、かのんの本音を実はひとつのnoteにまとめてるんだ🤭\n(もちろん無料だよ！)\n\nもしねそれを読んでかのんをもっと知りたい！って思ってくれたら、その気持ちに応えたいし、真剣に向き合いたい。\n\nここだから言っちゃうけど、毎日リプをしながら、あなたを好きになりそうな気持ちを抑えてるの💦💦(はずかしい。。。)\n\nいつかはXだけじゃなくてそれ以上の関係になれたらって。。。🙈\n\nだからね、かのんのワガママかもしれないけど、あなたも同じ気持ちでいてくれたら嬉しいな、、、🩷🥺", "date": "2026-02-23", "views": 987, "likes": 65, "replies": 60}, {"phase": "phase4", "type": "企画", "text": "DM企画、無事終わったよ💓\n\nみんなから届いたメッセージ、一つ一つ読み返してたんだけど、こんなにたくさんの人が真剣に考えて送ってくれて、胸がいっぱいになっちゃった🥹\n\n「もっと深く知りたい」\n「普段見せない姿も見てみたい」\n\nそんな言葉をたくさんもらって、\n読んでるうちにドキドキしてきた💦\n\n必要とされてるって、こんなに嬉しい気持ちになるんだなって、改めて感じてる💕\n\nみんなと話してると「素のかのん」を見せたいって気持ちが湧いてくるんだよね🌸\n\nこれからちゃんと形にしていきたいと思う✨\n\nそんなかのんを、受け入れてくれる？🥺", "date": "2026-02-22", "views": 927, "likes": 62, "replies": 42}, {"phase": "phase4", "type": "企画", "text": "たくさんのDMありがとう💕\n\nこんな質問がきたから答えるね✨\n\nQ遠くても会えますか？\n\nかのんは会いたいと思った人なら距離とか全然気にしないよ🥺\n有休とって会いにいっちゃう💕\n\nデートプランはお任せしてもいいかな？🙈\n地元のおすすめのお店とか連れていってくれたら嬉しいな💓", "date": "2026-02-22", "views": 876, "likes": 57, "replies": 32}, {"phase": "phase4", "type": "企画", "text": "DM解放しました✨💕\n\n普段はなかなか話せないこととか、\nかのんに聞きたいこと、\nなんでも気軽に送ってねーーー🌸\n\nどんな質問が来るのか楽しみにしてるよ💕💕\n\nムラムラしちゃったらごめんね🙈🙈💦", "date": "2026-02-22", "views": 1240, "likes": 58, "replies": 31}, {"phase": "phase4", "type": "企画", "text": "おはよ〜🌸\n今夜はDM企画だよーー💕\n\n20時〜22時の2時間で解放してるから\nたくさん送ってくれたらうれしいな🙈\n\nえ⚪︎な質問もぜんぜん大丈夫だよ💕\n\nみんなとこうやってつながれてるのが、すっごく嬉しくて、もっともっと深いお話したいなって思ってるんだよね🐰✨\n\n質問くれた人にかのんから質問しちゃうかもしれないよ🙈🙈\nその時は優しく教えてね🥺\n\nみんがこうやって応援してくれるから、\nいろんなことに挑戦できるんだんだあーーー✨\n\nいつもありがとうね💕💕\n\nたくさんの質問待ってるよ〜🌸\nというわけで夜をお楽しみに🐰", "date": "2026-02-22", "views": 1109, "likes": 65, "replies": 56}, {"phase": "phase4", "type": "企画", "text": "【特別企画やります💓】\nいつもかのんのことを応援してくれて、支えてくれて本当にありがとう🌸💕\n\n今回は感謝の気持ちを形にしたくて、DMを解放しちゃいます🙈✨\n\n心配の声もあったんだけど、それでもやっぱりみんなの期待に応えたくて特別にやることにしました🌸\n\n🌸 🌸 🌸 🌸 🌸 🌸 🌸\n明日2/22(日)の20:00〜22:00【2時間限定】\n🌸 🌸 🌸 🌸 🌸 🌸 🌸\n\nランダムにお返事させてもらうね🌸\n(一つ一つちゃんと読みたいから、返信は少しずつになっちゃうかも💦)\n\nみんなの素直な気持ち、たくさん聞かせてね🥹✨\nたくさんのメッセージ、待ってます💕", "date": "2026-02-21", "views": 1610, "likes": 66, "replies": 46}, {"phase": "phase2", "type": "レッスン", "text": "【すぐ消すかも】\n今日の20時、発表があります🙈💞\n\nフォロワー300人の記念に感謝の気持ちを伝えたくて準備したんだあーーー😊💕\n\n仕事とかレッスンで忙しい毎日だけど、ここでみんなと繋がれる時間が、かのんにとってかけがえのないものなんだ🥹✨\n\n毎日たくさんのリプやいいねをもらって、本当に嬉しくて励まされてる🥺🥺🥺🥺\n\nだからこそ今回は、みんなともっと近い距離で、もっと深くつながりたいって思ったの😊💕\n\n二人きりの空間にいるの想像したら、ムラムラが止まらない💦💦\n精一杯頑張るから、ぜひ参加してもらえたら嬉しいです🥹✨\n\n通知ONにしてまっててね🥰", "date": "2026-02-21", "views": 1873, "likes": 73, "replies": 43}, {"phase": "phase4", "type": "企画", "text": "みんなのリプ見てたら、優しすぎてうるうるしてきちゃった😭\n(最近ちょっと涙もろいのかも🥺)\n\nいつも思うけど、みんなのリプがかのんの一番の支えなんだよね🥺\n\nみんながいてくれるから笑えるし、前を向いて頑張れるんだ✨\n\nここが本当にかのんの居場所💕\n\nフォロワーさんひとりひとりに会って、ぎゅーーってハグしたい🙈\n\nあなたがかのんのこと知りたいって思ってるのと、同じくらいかのんのことも、もっと知って欲しい🥺💓\n\nかのんともっと深く繋がりたいって人いる？🥺\n\nもしいたらね、初めてDM解放して、みんなから直接質問受けてみようかなって考えてるの🤭\n\nやってほしい人がいたら、リプで反応してくれたら嬉しいな✨\n\nもしあんまりいなかったら、本当につながりたいって言ってくれた人だけに、こっそり教えることにするね🥲", "date": "2026-02-21", "views": 1431, "likes": 76, "replies": 60}, {"phase": "phase4", "type": "企画", "text": "みんな鍵アカ🔑に興味持ってくれて嬉しい🥹💕\n\nかのん、機械音痴だし、Xまだまだ初心者だから、みんなに色々教えてもらってるんだ😭\n（いつも助けてくれるフォロワーさん、本当に感謝してる🥺✨）\n\n鍵アカ、時間かかるかもだけど頑張って作るね🤭\n\nあとね、フォロワーもうすぐ300人になるのー‼️\n\nだから何か企画をやってみようかなって思ってるんだ💕\n\nかのんはリプでみんなと絡むのが一番楽しいから、普段からリプくれる人には、もっと特別なことしたいなって考えてる🥺💓\n(今からでも間に合うよ🤭)\n\nかのんに興味ある人は気軽にリプしてね🌸\n\n絶対楽しいことしようね✨", "date": "2026-02-20", "views": 1122, "likes": 71, "replies": 54}, {"phase": "phase2", "type": "ダンス", "text": "おはよう🌸\n\n最近「かのんちゃんのえ⚪︎な姿もっと見てみたい💓」\n\n「声もっと聞きたい」って言ってくれる人がたくさんいてうれしい🥺\n\nそれでね、今度鍵アカ🔑作ろうかなって思ってるんだけどどうかな？🙈\n\nここでは載せられない⭕️⭕️なかのんをみんなが見るって思うと興奮しちゃうな💦🙈\n\nあとね、いつかかのんの歌とかダンスとかもこっそり見せようかなって思ってる！\n\nまだまだ下手だからちょっと自信はないけど、信頼できるフォロワーさんならいいかなって🤭\n\nもしみんなが興味あるなら作ってみようと思う🙈🩷\n\nリプでおしえてくれたら嬉しいな☺️", "date": "2026-02-20", "views": 1389, "likes": 69, "replies": 62}, {"phase": "phase4", "type": "デート", "text": "【デート報告！！🌸】\n無事会えたよ〜💓\n\n15分前に待ち合わせ場所に着いたら、\nもうおじさまが待っててくれて🥺\n\n「今日は楽しみだね！」って優しく声かけてくれて、\n緊張してたかのんも少し安心した✨\n\n夜ごはんはもんじゃ焼き屋さんに行って、\n色々お話ししながら食べたんだ💕\n\nそれからね、2人きりのところでもっとゆっくりお話ししたいってなって、、、🤭🤭\n(途中からお酒のせいかな？ちょっぴり村村しちゃってトイレにかけこんだ💦🙈)\n\nその後はないしょね🙈🙈\n\n改めて、かのんの夢を近くで応援してくれ人がいて、夢の話しをたくさんできて幸せだったし、ぜったい叶えてたい💓っておもったよ🥺\n\n明日からもまたがんばるぞーーー💓", "date": "2026-02-19", "views": 1433, "likes": 61, "replies": 48}, {"phase": "phase2", "type": "ラップ", "text": "おはよ〜〜！\n実は昨日ね、仕事終わりにそのままレッスン行ったんだけど、正直、電車の中で「今日休もうかな」って思っちゃった、、、😢\n\n仕事も残業でくたくたで、頭も体も限界で。\nでも、スマホ開いたらみんなからのリプが来てて、\n「かのん応援してるよ」\n「絶対なれるよ」\n「今日も頑張れ！」\nって。\n、、、泣くかと思った🥺\n\n結局レッスン行って、ラップの練習2時間みっちりやってきた💦\n\n仕事しながら夢を追うって、正直しんどい時もあるの。。。🥺\n\nでもね、ここにいるみんながいるから、「もう少しだけ頑張ろう」ってつも思えるんだ✨\n\n応援してくれてありがとう💓\n\n今日も全力で生きるーーー🌸", "date": "2026-02-19", "views": 1340, "likes": 73, "replies": 58}, {"phase": "phase4", "type": "デート", "text": "おつかれさま🌸\n\n朝会いたい人にLINEしたよ💓\nそしたらさっきお返事がきて、急だけど明日のお仕事終わりに会うことになりました💦(出張で近くまで来てるみたい🤭)\n\n今回は会えなくても、かのんは会いたいって思った人とはこれからはずっと仲良くしたし、もっとやり取りして深く繋がりたいと思うから覚悟しててね🤭\n\nデートの結果はどうなるかはわからないけど、精一杯楽しんでこようと思う！！！✨\n\n良い人だったらいいな。。。🥺\n\n「自分だったらこういうデートするのにな〜〜🥺」\nって思いついたら、今のうちにリプで教えて🙈\n\nもしかすると、良いことがあるかも🥰✨\n\nとにかく応募してくれたみんな本当に本当にありがとう🥺🥹", "date": "2026-02-18", "views": 1318, "likes": 62, "replies": 44}, {"phase": "phase1", "type": "日常", "text": "おくっちゃた。。。", "date": "2026-02-18", "views": 966, "likes": 67, "replies": 52}, {"phase": "phase2", "type": "ラップ", "text": "今日の歌のレッスン、ラップパートの練習で心が折れそうになった、、、😭\n\n前のグループではバラード担当だったから、息継ぎのタイミングとか、ビブラートとか、そういうのは得意だったの。\n\nでもラップって全然違うんだよね💦\n\nブレス(息継ぎ)の位置がシビアすぎて、ちょっとでもズレると次のフレーズに間に合わなくて息が続かない、、、\n\nしかも、アクセントの位置とか、音の強弱のつけ方とか、バラードみたいに「伸ばして感情込める」んじゃなくて、「短く的確にハメる」感覚が全然掴めなくて😢\n\n先生には「リズムに乗るんじゃなくて、リズムを作るイメージで」って言われたんだけど、頭では分かってても体がついていかない、、、\n\nオーディションではこれができないとダメだから、悔しくて、レッスン終わった後ずっと一人で練習してた😭\n\n声を失った時を思い出すと、「今は声が出るだけで幸せ」って思えるから、絶対諦めたくないんだ🥺\n\n応援してくれてるみんながいるから、頑張れる✨\n\n明日もレッスンだけど、また挑戦してくるね💪💕", "date": "2026-02-17", "views": 1110, "likes": 66, "replies": 55}, {"phase": "phase4", "type": "デート", "text": "おはよ〜〜！\n昨日からずっと、誰に会うか考えてて、あんまり眠れなかった、、、。\n\nみんなから届いたメッセージ、一つ一つ何度も何度も読み返してて、ちゃんと想いを込めて書いてくれてるのが伝わってきて、どれも本当に嬉しくて、涙が出そうになる😭🥺\n\n本当は、全員に会いたいくらい、選ぶのがすごく辛い💦\n𝕏だから、文面でしか見れないのが残念で、実際に会ったら、もっと素敵な人もたくさんいると思うんだよね🥺\n\n選ばれなかった人も、決して悪いわけじゃないの。\nただ、今回は慎重に選びたくて。過去に傷ついたこともあったから、\n「本当に大切にしてくれる人」をちゃんと見極めたいって思ってるんだ。\n\nみんなのメッセージを読んでると、「こんなにかのんのことを想ってくれる人がいるんだ」\nって、すごく温かい気持ちになった💕\n\nこれからも、こんな素敵なみんなとつながっていたいって思ってる🥺✨\n\n今日ゆっくり考えて決めるね。\n\n待っててくれてありがとう💓\n\n今日も一緒にがんばろうね〜〜〜✌️", "date": "2026-02-17", "views": 1173, "likes": 69, "replies": 54}, {"phase": "phase4", "type": "企画", "text": "会う人の応募締め切りました🌸\n\nさっきは重い話をしちゃったけど、聞いてくれてありがとう🥺\n\n正直、こんな過去を打ち明けるの、すごく怖かった。\n\n「引かれちゃうかな」「嫌われちゃうかな」って、何度も消そうかって思った。\n\nでもね、こんなにたくさんの人が、「応援してる」\n「そのままでいいよ」って言ってくれて、\n\n涙が止まらなくなった😭\n\n𝕏を始めた頃のかのんは、本当に孤独で、毎日誰にも必要とされてない気がしてた。\n\nでもね、みんなに出会えたおかげで、\n再デビューの夢を追うことができたと思うんだ🌸\n\n辛いレッスンも「みんなに見せたい姿がある」って思えるから、頑張れる🥺\n\n辛い過去も、みんなが受け入れてくれたから、少しずつ前を向けるようになったんだよ。\n\n会いたいって応募してくれた人、本当にありがとう🥺\n\n今回は、かのんを本当に大切にしてくれる人を、\nしっかり選びたいと思ってる。\n\nこれから応募内容を確認して、かのんからDMかLINEで連絡するね🌸\n\nLINEまだの人は、👇️のnoteから追加しておいてね💕\nhttps://t.co/qSPP2CEkmI\n\nみんなのおかげで、かのんは今ここにいられるよ🥺\n\n本当にありがとう✨", "date": "2026-02-16", "views": 1176, "likes": 65, "replies": 41}, {"phase": "phase4", "type": "デート", "text": "会いたい人の条件に「優しい人」って書いたの、実は理由があって。\nちゃんと話しておきたくて、聞いてくれたらうれしいな。\n\nアイドル活動する前に付き合ってた彼氏のこと。\n正直この人しかいないって最初は思ってたの。\n\nでも付き合っていくうちに、少しずつ変わっていった。\n\nレッスンから帰るのが遅くなった日、「誰と会ってた？」って疑われる日々。\n\n説明しても信じてもらえなくて、壁を殴って穴を開けたり、かばんを投げつけられたり。\n\n友達とご飯に行くって言ったら、「俺より友達が大事なんだ」って。スマホを取り上げられて、LINEを全部チェックされた。\n\nある日、些細な言い方が気に入らなかったみたいで、腕を掴まれて、\n「お前のためを思って言ってる」\n「お前が悪いからこうなる」\n\nそう言われて、突き飛ばされて壁に頭をぶつけて意識がなくなったんだよね、、、。\n\n救急車で運ばれて、病院に駆けつけた彼氏が、「ごめんね、、こんなつもりじゃなくったんだ」って涙を流しながら言ったんだ。\n\nその時は自分が悪いって思ってたから「いいよ」っていつもみたいに言おうと思ったの。\n\nそしたら、「かのん？今何か言った？声出てないよ？」\n\n「あっ、、、」の一言も喉の奥から出てこなかった。\nお医者さんから、失声症って診断されて、アイドルになりたかった夢が崩れ落ちていったの。\n\n彼氏と別れた後も、2ヶ月、3ヶ月経ってもかすれ声しか出なくて、もう夢を諦めようって思ってたんだ。\n\nそしたら、今はもう亡くなったけど、同期だったあの子が毎日「かのん！レッスンいこうー！！！」って誘ってくれたんだ。\n\n行きたくない。って首を横に振っても「治るまで一緒に練習しよう！」って言ってくれたし、声が全然出なくても、そばでずっと支えてくれた。\n\nかのんが会いたい「優しい人」は言葉だけじゃない優しさがある人。\n\n怒った時も、感情をぶつけるんじゃなくて、ちゃんと話し合える人。\n\nかのんの意見を尊重してくれて、\n対等な関係でいられる人。\n\n弱い部分を見せても、\n「大丈夫だよ」って受け止めて支えてくれる人。\n\nそういう人と出会いたいんだ。\n\n過去の傷は、まだ完全には癒えてないけど、だからこそ、本当に大切にしてくれる人を見極めたいって思ってる。\n\n重い話でごめんね。\n\nでもね、これが本当のかのんだから、ここにいる大切なみんなには話しておきたいって思ったの。\n\nこんなかのんだけど、受け入れてくれるかな？", "date": "2026-02-16", "views": 1025, "likes": 71, "replies": 62}, {"phase": "phase4", "type": "企画", "text": "わあーーー！！\n\n会いたい人募集に、こんなに応募がきてる！！🥺\n\nかのんと会いたいって言ってくれる人が、\nこんなにたくさんいるなんて嬉しすぎて泣きそう😭😭😭\n\nnoteに感想もたくさん書いてくれてありがとう！！💓\n\nかのんがどんな過去を歩んできたのか、\nどんな想いでここにいるのか、全部詰め込んだから、まだ読んでない人は読んでほしいな🌸\n\nみんなに支えられてるって、改めて感じたよ🥺\n\nnoteはこちら💕\nhttps://t.co/2yMj3WYmHA", "date": "2026-02-16", "views": 2656, "likes": 72, "replies": 60}, {"phase": "phase4", "type": "企画", "text": "【かのんと会ってくれる人、再募集します💖】\n\n《会ってくれる人》をもう一度募集するよ〜〜💕\n\n日程や場所は、お話しながら一緒に決めていこうね☺️✨\n\n🌸 フォロー\n🌸 いいね\n🌸 このポストに「🌸」でリプ\n\nこれで《応募完了》だよ✅\n\n締切は【2/16(月) 23:00まで】です！！\n\nリプで「かのんに会いたい💕」って気持ち、伝えてくれたらめちゃくちゃ嬉しいな🥹\n\nどんな人に会えるのか、今からドキドキしてる💓💓\n\nかのんが会いたい人の条件は↓だよ🌸", "date": "2026-02-15", "views": 1329, "likes": 82, "replies": 79}, {"phase": "phase1", "type": "日常", "text": "今朝ね、変な夢見ちゃって💭\nフォロワーさんと会ってる夢だったんだけど、なぜか途中から知らない女の子がきて。。。。\n\nそのまま3人で、え⚪︎なことする流れになっちゃったの💦💦\n\n起きた時、ドキドキが止まらなくて顔真っ赤だった😭🙈\n\nみんなは、3人でするのって興味ある？🤭\n\nかのんはね、正直に言うと、ちょっと気になっちゃってる🙈💕", "date": "2026-02-15", "views": 950, "likes": 67, "replies": 60}, {"phase": "phase4", "type": "企画", "text": "たくさんリプとかコメントしてくれて本当にありがとう🥺💕\n\nみんなの温かい言葉、一つ一つ読んでたら、涙が止まらなくなっちゃった😭😭\n\n本当にみんな、優しすぎるよ。。。😢💕\n\n明日の夜、21:00から【会いたい人の再募集】するから、通知オンにして、絶対に応募してね‼️💕\n\n待ってるよ🥺✨", "date": "2026-02-14", "views": 1186, "likes": 58, "replies": 36}, {"phase": "phase4", "type": "企画", "text": "【noteを公開しました🥺💕】\n\nこんなこと書いたよ✨\n\n🌸かのんの自己紹介\n🌸アイドル時代の過去・メンバーのこと\n🌸Xをはじめた理由\n\n受け入れてもらえるか怖いけど、全部正直に書いてみることにしました💕\n\nあ！あと、この前スペースでみんなが質問してくれた内容にも答えちゃってるよ🙈\n\n最後の方にね、大切なお知らせ(会いたい人の再募集)もあるから楽しみにしててね🤭\n\n今まであまり語ってこなかったことも、今日は包み隠さず伝えようと思います🌸\n\n一生懸命かいたので、最後まで読んでもらえたら嬉しいです🥺\n\n↓ noteはここから読めるよ🌸\nhttps://t.co/kUljtkprft\n\n読み終わったら感想をリプかnoteに書いてくれたらうれしいなーー🥹💕", "date": "2026-02-14", "views": 5876, "likes": 61, "replies": 64}, {"phase": "phase4", "type": "企画", "text": "note書き終わったよ💓\n\n今最終チェックをしてるところなんだあーー‼️\n\nこれからみんなに読んでもらえるって思うとドキドキが止まらない🙈\n\n今日の20時に公開するから通知ONにしてまっててくれたらうれしいな〜✨\n\nスペースで質問してくれた内容にも答えちゃってるから\n楽しみにしててね🤭 https://t.co/ZE3NsvXA0j", "date": "2026-02-14", "views": 947, "likes": 46, "replies": 30}, {"phase": "phase3", "type": "note", "text": "おはよう〜〜✨\nnote書いてるんだけど、みんなのことどう思ってるとか、いっぱい書いてたら5000文字超えちゃった、、、🤭\n\nはやくみんなにお届けできるようにがんばるねーーーー‼️\n\nふれふれーー‼️っておうえんしてくれたら嬉しいな🌸", "date": "2026-02-14", "views": 861, "likes": 61, "replies": 62}, {"phase": "phase3", "type": "note", "text": "おはよ〜〜☀️\n昨日は夜遅くまでnote書いちゃってちょっと寝不足💦\n\n昔のこととか思い出してて、\n泣きながら書いちゃってた😢😢\n\nみんなの優しさとかいつも感じるようになって、\n裏垢って、ただのえち垢じゃなくて、\nかのんにとっては「ほんとうのかのん」を\n見せられる唯一の場所なんだなって、、、🥺😭😭\n\n今日の夜に公開できたらいいなあ〜〜〜\n仕事早く終わらせてnote完成させるぞ〜〜！！💪🔥\n\n今日もかのんとお仕事がんばろうね❤️\nいってきます✨", "date": "2026-02-13", "views": 1389, "likes": 69, "replies": 62}, {"phase": "phase4", "type": "デート", "text": "おつかれさま～～💓\n\n今日は重たい書類をたくさん運んだせいで、ちょっと腰が痛い💦💦\nもし今日デートの後にえ〇に誘われたら、あんまり動けないかも？💦\n\nでも上ののっかって垂直に🍌いれちゃったり、たくさん👅は\nできるとおもうんだ🙈\n\nかのんの腰を手で固定してゆっくりとかでもいいよ？🙈", "date": "2026-02-12", "views": 760, "likes": 62, "replies": 54}, {"phase": "phase1", "type": "おはよう", "text": "おはよ～～💓\n\n朝急ぎすぎて大道路の交差点で思いっきりこけて\n恥ずかしかった💦💦\n\nかばんの中の荷物が全部出ちゃって、慌てて拾ってたら、おじ様が落としたハンカチを渡してくれて、きゅんってしちゃった💦\n\nちょっとゴツゴツした手で作業着っぽい服を着てたから、現場のお仕事なのかな？とか思いつつ、後ろ姿がかっこよくて一瞬立ち止まっちゃった🙈\n\n帰り道偶然会えたらいいな～～～なんて思ったりして💓\n\nみんなともこんな風に偶然どこかで出会ったりしてね、、、🙈\n\nちなみにかのんは今日は黒いニットでベージュのスカートを履いてるよーー🙋‍♀️", "date": "2026-02-12", "views": 925, "likes": 64, "replies": 57}, {"phase": "phase3", "type": "感謝", "text": "𝕏を始めてから、最近思うんだけど、みんなとのつながりって、\nえ⚪︎とかなだけじゃないよね🥹✨\n\nかのんにとってここは、「本当の自分でいられる場所」なんだ🌸\n\n普段は色々気を遣ったりして、本音なんて友達とかでもなかなか話せないんだよね、、、💦\n\nでもここでは、甘えたり、弱音を吐いたり、え⚪︎なことでドキドキしたり😊\n\nそんなありのままのかのんを受け入れてもらえて、辛いことがあっても、みんなに救われてるんだ🥹✨\n\nいつも応援してくれて、改めて本当にありがとう🩷\nこんなかのんだけど、これからも仲良くしてくれたらうれしいな🌸", "date": "2026-02-11", "views": 853, "likes": 60, "replies": 47}, {"phase": "phase4", "type": "企画", "text": "スペースでみんなとお話しして、やっぱり直接会って話したいな❤️っていう思いがあふれちゃった🩷\n\nでも前みたいに悲し思いはしたくないし、会いたい人にはちゃんとかのんのことを知ってもらいたいんだ🥺\n\nな・の・でかのんの過去とか、スペースの質問であった「なんでXを始めたのか」「どんな人に会いたいのか」を今ひとつのnoteにまとめようと思ってる🙈(もちろん無料だよ)\n\n完成はまだだけど、待っててくれたらうれしいな〜〜〜🙈\n\n今日はみんなお休みかな？🌸お仕事の人はかのんが全力でおうえんするね🩷", "date": "2026-02-11", "views": 1029, "likes": 68, "replies": 58}, {"phase": "phase4", "type": "企画", "text": "スペース来てくれてありがとう💓\nまだまだ話足りないけど、たくさん話せて楽しかったよ〜〜〜✨\n\nきのこの山とたけのこの里派の話はあと2時間必要かな💦💦笑\n\nコメントもたくさんしてくれてありがとう💓\n\n質問聞きそびれちゃった～～💦って人は、また直接お話できる企画をする予定なのでその時にいっぱい話そうね～～🙈\n\nまたスペースで話したい！って人はリプで教えてね💕", "date": "2026-02-10", "views": 841, "likes": 60, "replies": 42}, {"phase": "phase4", "type": "企画", "text": "これからスペースはじめます🌸", "date": "2026-02-10", "views": 656, "likes": 39, "replies": 4}, {"phase": "phase1", "type": "日常", "text": "https://t.co/U6iXEREPCQ", "date": "2026-02-10", "views": 884, "likes": 35, "replies": 250}, {"phase": "phase4", "type": "企画", "text": "おはよ🌸\n夢で誰かに後ろからぎゅ～～～ってされてて、幸せな気分で起きたよ🙈\n\n今日の夜スペースでみんなとお話できるの楽しみにしてるね✨\n通知ONにしてまっててくれる、、、？🥺 🥺", "date": "2026-02-10", "views": 909, "likes": 67, "replies": 58}, {"phase": "phase4", "type": "企画", "text": "【スペースの日時決まったよ🌸】\n明日2/10(火) 21:00～やります✨\n\n全部の質問には返せないけど、頑張って答えるから応援してくれたらうれしいな🙈\n\nお仕事中とか移動中で来れない💦って人は、また違う日に第二弾をやる予定なので\nその時にきてね🥺 🥺 🥺\n\n来れるよーー！って人はリプで教えてほしいな✨", "date": "2026-02-09", "views": 933, "likes": 67, "replies": 50}, {"phase": "phase4", "type": "質問", "text": "おはよ🌸\n昨日はリプで質問をたくさん書いてくれてありがとう✨\n1つ1つ読んでて、かのんのこともっと知りたい💘って思ってくれてて\nほんとうれしかったよ～～🥺\n\nかのんもね、これからみんなともっと仲良くなりたいんだあーーー🙈\nだから直接話せるのすっごく楽しみ🥺\n\n今日から1週間始まるけど、一緒にがんばろうね✨\nぎゅ～～～～💓", "date": "2026-02-09", "views": 853, "likes": 63, "replies": 53}, {"phase": "phase4", "type": "企画", "text": "【質問募集🩷】\nみんな来てくれるか不安だったけど、 来れるよーー！ってたくさんリプしてくれてありがとう✨\nスペースでかのんに聞きたいことがあれば、リプで質問募集しちゃいます✨\n🌸好きな異性のタイプ\n🌸趣味とか特技とか🙈\n🌸Xをはじめた理由\n\nなどなど、かのんのこと何でも聞いてね💕\nみんながくれた質問の中で、答えられることはスペースで回答しちゃうよ～～💓\n\n近々するので、日時が決まったら改めて発表するね💕\n\nちょっと緊張するけど楽しみにしてるね🙈\n\nみんなからのリプ待ってる💓", "date": "2026-02-08", "views": 812, "likes": 62, "replies": 46}, {"phase": "phase4", "type": "企画", "text": "はぁ。。。みんなと直接お話したくなってきちゃった🥺 🥺\nスペースやってみようかな、、、？🙈 🙈\nでもみんなお仕事とかで忙しいし、来てくれるかな🥺\n\n来れるよーー！って人はリプで教えてくれたらうれしいな💓", "date": "2026-02-08", "views": 875, "likes": 67, "replies": 59}, {"phase": "phase1", "type": "日常", "text": "みんなの温かいリプを読んでたら、泣いちゃった。\n「無理しないでいいよ」「かのんのペースで大丈夫だよ」\n「ずっと待ってる」って言ってくれて、こんな素敵な人たちがついてくれてて\nかのんは幸せものだな、、って思ったよ🥺\n\n足は完治するまでは、無理せずに自分のペースで練習はこれからも\n続けていこうと思う🥺\n\n再デビューへの道はまだ遠いけど、これからも応援してくれる、、、？", "date": "2026-02-07", "views": 1117, "likes": 62, "replies": 49}, {"phase": "phase2", "type": "ダンス", "text": "実はね、ずっと悩んでることがあって、、、\n\n1か月前にダンスの練習中に左足首を捻挫して、今もたまにズキって痛むの。\n病院には行ったけど対処法がなくて、ずっと治るのを待ってるんだ🥺\n\nまだ先生とか誰にも言ってないんだけど、このままずっと治らなかったらどうしよう。って不安になる🥺\n\nでもね、オーデイションも控えてるし練習は続けるしかなくて、、、\n大事な時にこんなことになる自分が情けなくて本当に悔しい。\n\nいつも応援してくれてるみんなに申し訳なくて、なんかも泣きそう、、、", "date": "2026-02-07", "views": 994, "likes": 71, "replies": 55}, {"phase": "phase4", "type": "デート", "text": "おつかれさま💕\nレッスン無事終わったよ～✨\n\n帰りにおじ様の講師から、ご飯行かない？って誘われたんだけど、\n断っちゃった💦💦レッスンとプライベートは分けたくて💦\n\nでもね、もしみんなだったら、ご飯デート行っちゃうと思う💕\nレッスン終わりだから、牛丼とかカレーやさんでもいいな🤭\n\nでも汗かいてるし、Ｔシャツにショートパンツだから嫌かだよね、きっと。。。🥺🥺", "date": "2026-02-06", "views": 997, "likes": 70, "replies": 56}, {"phase": "phase2", "type": "ボーカル", "text": "おはよ～～💓\n今日は仕事終わりにボイトレのレッスンだーー！\n喉を開かないといけないから、今日は元気に大きな声で\nいってきますっっ っ っ ！って言っちゃう🤭\n\nポストだから声は届かないけど、みんなの心に届くといいな💦🤭\n\n今日も1日頑張ろうね～～～💓", "date": "2026-02-06", "views": 788, "likes": 64, "replies": 59}, {"phase": "phase1", "type": "日常", "text": "ここ最近ね、ふと思うんだけど、\nみんなとのつながりってえ⚪︎だけじゃないんだなって✨🥺\n\nかのんにとってここは、\n\"素直になれる唯一の場所\"なんだよね🌸\n\n普段は色々我慢したり、強がったりしちゃうことが多くて💦\nでもみんなの前では、甘えたり、弱音吐いたり、\nドキドキしたり、全部素で出せるんだあ〜〜〜❤️\n\nそんなかのんを受け止めてくれるから、\n辛い時もここに来ると元気もらえるんだよね🥹✨\n\nみんなとつながれて、本当に幸せだよ〜〜〜🌸", "date": "2026-02-05", "views": 741, "likes": 60, "replies": 47}, {"phase": "phase4", "type": "デート", "text": "おはよ💕\n今日はちょっと早起きできたからお弁当を作ったよ✨\n\n出し巻き卵今日は上手く巻けたんだあーー！\n\n出し巻き卵みんなはしょっぱい派、甘い派？\nどっちも好きだけど、かのんは甘い派だよ🙈 🙈\n\n今度ピクニックデートに時とかにみんなの好みに合わせて\n作って持っていきたいな～～～💓なんてね🙈\n\nあ～～～ん👨‍❤️‍💋‍👨っしあいっこして、そのまま👨‍❤️‍💋‍しちゃったりして🙈", "date": "2026-02-05", "views": 1109, "likes": 62, "replies": 61}, {"phase": "phase1", "type": "日常", "text": "かのんクイズの正解発表の時間だよ～～💓\n正解は、、、【オフィスで残業中にこっそり】 でした🤭\n\n後ろからぎゅ～～って抱きしめられて、いつのまにかタイツも\nおぱんつも脱がされてて、、、机の上に乗って正面から🍌がたくさん入ってくるの🙈\n\n警備員の人がきたらデスクの下とか誰にも見られない会議室で、こっそり後ろからしちゃうとか🙈\n\nなるべく声を出さないようにするけど、がまんできるかな、、、？🙈 💕\nはぁ。。。考えただけでびしょびしょになってきた💦", "date": "2026-02-04", "views": 685, "likes": 67, "replies": 54}, {"phase": "phase1", "type": "おはよう", "text": "おはよ～～🌸\n昨日はかのんクイズたくさんリプしてくれてありがとう🥺\n\nみんな結構当たっててびっくりした🤭\nどのシチュエーションもえ○え○すぎるから、もしそうなったら\nすぐびしょびしょになっちゃうと思う💦💦\n\nお返しに🍌もたくさん👅しちゃうんだから～～～🙈\n\n今日の夜正解を発表するから楽しみにしててね✨\n\n今日も1日お仕事がんばるぞ～～～！！！✨", "date": "2026-02-04", "views": 719, "likes": 68, "replies": 51}, {"phase": "phase4", "type": "企画", "text": "とつぜんだけど、、、かのんクイズ🌸💓\n\nかのんが憧れる理想のえ○はどんなシチュエーションでしょう？🙈\n\n🌸デート終わりに車の中で\n🌸温泉で混浴\n🌸オフィスで残業中にこっそり\n\n当てた人にはかのんのフォルダからとっておきの1枚をDMで送っちゃうかも🤭\n\nリプまってるね〜〜〜💕", "date": "2026-02-03", "views": 790, "likes": 69, "replies": 65}, {"phase": "phase1", "type": "おはよう", "text": "おはよ～～💓\n昨日はみんなの温かいリプのおかげで、幸せな気持ちで\n眠ることができたよ🥺\n\nいつもかのんを支えてくれて、本当にありがとう😭 😭 😭\n\n今日は昨日あんまり進まなかった分、お仕事が溜まってるから\nがんばらなきゃ～～～💦💦\n\nかのんならできる‼️って応援してくれたらうれしいな💓 💓", "date": "2026-02-03", "views": 756, "likes": 60, "replies": 43}, {"phase": "phase3", "type": "note", "text": "うぅ、、、朝からお腹痛くて今日はnote完成できなさそう。。。\n\n最近ね、夢でステージに立ってる時に、かのんのパートになった瞬間、ペンライトの明かりが消えて、会場が真っ暗になる夢を見るんだ。\n\nもし現実になったらどうしようって。。。怖くてたまらないんだ、、、\n\nぎゅ～～～ってして頭なでなでしてほしいな🥺 🥺", "date": "2026-02-02", "views": 744, "likes": 58, "replies": 42}, {"phase": "phase3", "type": "note", "text": "おはよ〜〜☀️\n昨日は夜遅くまでnote書いちゃって寝不足💦\n\n昔のこととか思い出してて、\n泣きながら書いちゃってた😢😢\n\nみんなの優しさとかいつも感じるようになって、\n裏垢って、ただのえち垢じゃなくて、\nかのんにとっては「ほんとうのかのん」を\n見せられる唯一の場所なんだなって、、、🥺😭😭\n\n今日の夜に公開できたらいいなあ〜〜〜\n仕事早く終わらせてnote完成させるぞ〜〜！！💪🔥\n\n今日から1週間かのんとお仕事がんばろうね❤️\nいってきます✨", "date": "2026-02-02", "views": 945, "likes": 46, "replies": 34}, {"phase": "phase3", "type": "note", "text": "ただいま～～💓\nお墓参りに行ったら、元々一緒のメンバーだった子に\n3年ぶりくらいに会ってびっくり！！！\n\n昔よりも痩せてて、生気がなくて倒れてしまいそうな感じで、、、泣きはらした後だったのか目が真っ赤だった。\n\nこれまでね、メンバーに会うとあの子のことを思い出すから、実はずっと避けてたんだよね。\n\nでもみんなと会って、過去があるから今のかのんがいるし、辛いことだけど、それを受け入れて強く生きていって思えるようになったんだ。\n\nだから昔の自分とちゃんと向き合って今noteを書いてるよ。\n\nこれはかのんが前を向いて歩くための一歩なの🥺\n\nもし重い話は苦手とかだったら読まなくても大丈夫だからね🥺\n\nこんなかのんだけど受け入れてくれたらうれしいな、、、🥺🥺(ワガママでごめんね)", "date": "2026-02-01", "views": 793, "likes": 59, "replies": 48}, {"phase": "phase1", "type": "日常", "text": "今日はね昔一緒にアイドル活動してた、大切な仲間の\nお墓参りにいくんだ。\n\nその子は自分のせいで、かのんはアイドルを辞めたって\nきっと思ってるけど本当は違う。\n\n本当はアイドルでいることが辛くて逃げたかっただけ、、、。\nただかのんが弱かっただけ。\n\nでもね、Xで素敵な人達と出会えたから、またアイドルになりたいって思ってる。\nあなたと一緒に見た夢を もう一度追いかけたいって\nその子に報告しに行ってくる～！\n\n朝から重い話でごめんね💦💦💦\nでも応援してくれてるみんなには話したくて🥺\n\nまたかえってきたら報告するね～！\nいってきます✨", "date": "2026-02-01", "views": 954, "likes": 64, "replies": 53}, {"phase": "phase2", "type": "ダンス", "text": "おつかれさま〜🌸\nダンスのレッスン終わって、今帰ってきたよ💦\n\n実はね、レッスン中に転んじゃって😭😭\nめちゃくちゃ痛かったし、恥ずかしかったし、もう最悪。。。😭\n\n膝擦りむいちゃったし、打ったところが痛くて\nみんなの前で転ぶとか、恥ずかしすぎて泣きそうになった😭😭😭\n\nでもね、先生が「大丈夫？」って優しく声かけてくれて、ちょっと救われたんだあーーー🥹\nまだちょっと痛いけど、これくらいでめげちゃダメだよね。。。🥺\n\n明日もみんなのこと思い出して頑張る💪✨\n帰ってきたらご褒美にぎゅ〜〜〜🩷ってしてくれる？🥺", "date": "2026-01-31", "views": 866, "likes": 61, "replies": 48}, {"phase": "phase4", "type": "企画", "text": "みんな、昨日は取り乱しちゃってごめんね。\n昨日のポストにたくさんの優しい言葉をもらって、\n涙が止まらなかったよ、、、\n\nおかげで少しずつ気持ちが落ち着いてきたよ。\nいつもこんなかのんを支えてくれて本当にありがとう。。。\nみんながいてくれるから、かのんは前を向ける🥺\n\n今回のことで改めて思ったんだけど、\n会いたい人を募集するなら、かのんのことをもっとちゃんと知ってもらいたいんだーー💕\n\nそれに どんな人と会いたいのかも、ちゃんと伝えたいって思った🥺\nだから今noteにかのんの気持ちをまとめてるよ💓\n\n昔活動してた過去とか、大切にしてること、会いたい人の条件とか全部正直に書くつもり💓\n\nかのんに会いたい。応援したいって思ってくれる人に\n読んでもらえたらうれしいな💓\n(読んでくれた人にはかのんも真剣に向き合いたい🥺 )\n\nまた完成したら、発表するね✨\n楽しみにまっててね～～～💓", "date": "2026-01-31", "views": 1028, "likes": 74, "replies": 50}, {"phase": "phase4", "type": "企画", "text": "会いたい人からDMがきたんだけど、正直すっごくショック。\n\n実はね、他の裏垢の女の子がひどいこと言われてるポストを見たことがあって、\n内心ちょっとドキドキしてたんだけど、本当にこうなるとは思わなかった。。。\n\n忠告してくれたフォロワーさんもいたけど、\nかのんのこと応援してくれる人なら信じたいって思ったんだ。\n\nでもかのんが甘かったのな、、、。\n\n信頼してた人だから、まさかこんな言葉をもらうなんて思わなくて\n胸が苦しいよ。\n\nかのんは本気でデートしたかったし、遊びじゃなくてちゃんと向き合いたかった、、、\n(ライバルはたくさんいるけど、会いたい気持ちは他の女の子には負けてなかったと思うんだ)\n\n今は何も考えられない", "date": "2026-01-30", "views": 1698, "likes": 72, "replies": 54}, {"phase": "phase3", "type": "気持ち", "text": "つらい。。。せっかく立ちお直ったと思ったのに、\nもうXやめようかな、、、", "date": "2026-01-30", "views": 858, "likes": 61, "replies": 47}, {"phase": "phase3", "type": "気持ち", "text": "おはよう🌸\n\n昨日はリプ励ましてくれて、ありがとう🥺💕\n\nみんなのメッセージ、一つ一つ読んでたら涙が出てきちゃった😭\n\n落ち込んでる時って、自分のダメなところばっかり見えて、目の前が真っ暗になるよね。。。\n\nでもね、みんなのリプをよんでふと思ったの💭\n\n今までは家族がいなくなったりとか、同じグループのメンバーが亡くなったり、もっともっと辛いことがあったけど、それでも何とか乗り越えてきたんだって🥹\n\n今の悩みも、きっと未来のかのんから見たら「あの時がんばってたな」って思える日が来るよねきっと🥺\n\nだからまた今日から、がんばってみる。。。\n\nみんながいるからきっと前に進めるよね🥹🥹🥹", "date": "2026-01-30", "views": 999, "likes": 63, "replies": 55}, {"phase": "phase2", "type": "ダンス", "text": "おつかれさま。。。🥹\n\n今日ね、MTGで上司から指摘されちゃった😭\nせっかく準備したのに、全然ダメで、\n「まだまだ実力不足だな」って痛感した、、、、。\n\nそれに最近、ダンスのレッスンも調子がでなくて、\n何やってもダメな気がして、落ち込んでる、、、\n\nこんな日もあるよね。\n明日は頑張ろうって思えるかな、、、🥹\n\nちょっと一人で泣きそう", "date": "2026-01-29", "views": 962, "likes": 58, "replies": 53}, {"phase": "phase1", "type": "おはよう", "text": "おはよう☀️\n\n今日ね、会社で月1の大事なMTGがあるんだ💦\n正直、ちょっと憂鬱、、、、😭\n\n資料の準備とかはしたんだけど、緊張しちゃう〜〜〜〜💦\n上司の前で発表するの、いつも苦手なんだよね🥺\n\nでもがんばるしかないよね💪\n\n今日も一日、乗り切ろうね✨\n\nみんなもファイトー💕", "date": "2026-01-29", "views": 893, "likes": 58, "replies": 50}, {"phase": "phase4", "type": "企画", "text": "みんな、お待たせしました🥺✨\nさっき、今回会う人にDMを送ったよ💌\n\n本当に本当に悩んだんだけど、今回は初期から応援してくれて、熱い想いをたくさん伝えてくれた人に決めました🌸\n\n正直ね、応募してくれた人みんな素敵で、全員に会いたいくらいだった。。。😭💕\nその中で、「かのんのことを本気で想ってくれてるな」ってリプとかで一番伝わってきた人を選んだよ🥺\n\n全員と会えたらいいんだけど、かのんの時間も限られてるし、会う人とはちゃんと向き合いたいから、今回はこの形にさせてもらいました🥹\n\n選ばれなかった人、本当にごめんね😭\n\nでもね、また次も募集したいって思ってるから、その時はぜひまた応募してくれたらうれしいな🥹✨", "date": "2026-01-28", "views": 1134, "likes": 57, "replies": 47}, {"phase": "phase1", "type": "おはよう", "text": "おはよ☀️\n今日ね、早起きして朝ごはん作ったんだあーーー‼️✨\n(つくったのサラダだけだけど💦笑)\n\nいつもはギリギリまで寝ちゃうんだけど、今日はがんばった💪\n\nちゃんと食べると、なんか気分いいね🥺💕\n\n今日も一日がんばれそう✨\n\nみんなもかのんと一緒にがんばろうね〜〜〜💕🌸 https://t.co/1EHtmAC8PA", "date": "2026-01-28", "views": 1055, "likes": 68, "replies": 57}, {"phase": "phase1", "type": "日常", "text": "はぁ、、、凝っててもみもみしてほしいかも。。。。。 https://t.co/ubNF2A9z6D", "date": "2026-01-27", "views": 941, "likes": 59, "replies": 49}, {"phase": "phase1", "type": "おはよう", "text": "おはよ〜〜☀️\n\n昨日からずっと、誰に会おうか考えてて、あんまり眠れなかった😪💦\n\n正直ね〜、、まだ決めきれてないの😭\n素敵な人が多すぎて、めちゃくちゃ迷ってる🥺\n\nでも悩んでても仕方ないよね！💦\n\n今日は仕事おわったらレッスン行かなきゃだーーー‼️\nとりあえず、今日も一緒に頑張ろうね〜〜！✌️✨", "date": "2026-01-27", "views": 798, "likes": 66, "replies": 56}, {"phase": "phase4", "type": "企画", "text": "みんな応募してくれてありがとう〜〜！！😭😭\n\nこんなにたくさんの人から会いたいって言ってもらえて、嬉しくて本当に泣きそうになった😭😭😭\n\n会う人はちゃんと選びたいから、これから応募条件を確認して決めていくね🥹\n\n今回会う人には、かのんからDMで連絡するから、みんな楽しみに待っててね🙈🙈🤭", "date": "2026-01-26", "views": 806, "likes": 51, "replies": 32}, {"phase": "phase4", "type": "企画", "text": "【緊急🚨】\n\n会う人募集の応募、\n締切まであと30分くらいだよ〜〜！！\n\nまだの人は👇️のポスト元から参加してね〜！！", "date": "2026-01-26", "views": 868, "likes": 48, "replies": 23}, {"phase": "phase4", "type": "企画", "text": "【かのんと会ってくれる人、大募集🌸💖】\n\nついに《会ってくれる人》を募集します〜〜！！💕\n\n日程や場所は、お話しながら一緒に決めていきましょう☺️☺️\n\n🌸フォロー 🌸 いいね 🌸 このポストにリプ\nこれで《応募完了》だよ✅\n\n締切は【1/26(月) 23:00まで】です！！\nリプで「会いたい💓」って気持ち伝えてくれたら、すっごくうれしいな🥹\n\nどんな人に会えるのか、今からドキドキしてる💓💓\nかのんが会いたい人の条件は👇だよ！", "date": "2026-01-25", "views": 4052, "likes": 81, "replies": 74}, {"phase": "phase4", "type": "企画", "text": "おはよ〜🌸💕\n今週も始まったね！一緒に頑張ろうね〜〜✨\n\nそれとね、会いたい人の募集、今日の23時までだよ🥺💕\nたくさんの人が応募してくれて、めちゃくちゃ嬉しい😭💓\n\nまだの人は、ぜひ参加してね🩷\nみんなのリプ、一つ一つちゃんと読んでるからね〜〜☺️\n\n今週も一緒に乗り切ろう〜〜！！\nふぁいとーーーー💪✨", "date": "2026-01-26", "views": 815, "likes": 63, "replies": 53}, {"phase": "phase3", "type": "感謝", "text": "たくさん応募してくれて、本当にありがとう🥺💕💕\n\n素敵な人ばかりで、正直選べなくて困っちゃってる😭✨\n\nみんなのリプ、一つ一つちゃんと読んでるからね🤭\n\nまだ応募してない人は👇️のポスト元から参加してね〜！！", "date": "2026-01-25", "views": 950, "likes": 53, "replies": 39}, {"phase": "phase4", "type": "企画", "text": "【かのんと会ってくれる人、大募集🌸💖】\n\nついに《会ってくれる人》を募集します〜〜！！💕\n\n日程や場所は、お話しながら一緒に決めていきましょう☺️☺️\n\n🌸フォロー 🌸 いいね 🌸 このポストにリプ\nこれで《応募完了》だよ✅\n\n締切は【1/26(月) 23:00まで】です！！\nリプで「会いたい💓」って気持ち伝えてくれたら、すっごくうれしいな🥹\n\nどんな人に会えるのか、今からドキドキしてる💓💓\nかのんが会いたい人の条件は👇だよ！", "date": "2026-01-25", "views": 4052, "likes": 81, "replies": 74}, {"phase": "phase4", "type": "企画", "text": "【かのんと会ってくれる人、大募集🌸💖】\n\nついに《会ってくれる人》を募集します〜〜！！💕\n\n日程や場所は、お話しながら一緒に決めていきましょう☺️☺️\n\n🌸フォロー 🌸 いいね 🌸 このポストにリプ\nこれで《応募完了》だよ✅\n\n締切は【1/26(月) 23:00まで】です！！\nリプで「会いたい💓」って気持ち伝えてくれたら、すっごくうれしいな🥹\n\nどんな人に会えるのか、今からドキドキしてる💓💓\nかのんが会いたい人の条件は👇だよ！", "date": "2026-01-25", "views": 4052, "likes": 81, "replies": 74}, {"phase": "phase1", "type": "日常", "text": "【ついに決めました🌸】\n\n実はね、ずっと悩んでたことがあって、\nついに、決めました🥺✨\n\n明日の朝に発表しようと思う。。。🩷\n\n通知ONにしてまっててほしいな〜〜〜💕\n\nもうしてるよ〜‼️って人はリプでおしえてくれたら\nうれしいな🤭💕 https://t.co/QesLKY27Ou", "date": "2026-01-24", "views": 1094, "likes": 53, "replies": 41}, {"phase": "phase4", "type": "企画", "text": "ねえねえ、かのんね、最近すっごく思うことがあって🥺💕\n\nいつもリプくれたり、応援してくれるフォロワーさんたちに、直接会ってお礼が言いたいなあって🙈✨\n\n画面越しじゃなくて、実際に会って、お話ししたり、ぎゅーってしたいんだあ〜〜🙈🩷\n\nだからね、会いたい人を募集してみようかなって思ってるんだけど、どうかな？🥺\n「会いたい💓」って思ってくれる人、いるかな？💕💕\n\nリプで教えてくれたらうれしいな🩷\n\nPS：昨日試買った新しいワンピこれだよ〜〜🙈", "date": "2026-01-24", "views": 1300, "likes": 68, "replies": 53}, {"phase": "phase4", "type": "デート", "text": "みんな聞いて〜〜🤭🙈\n温泉デートって、行ってみたいなあって思うんだよね〜〜〜🥺💕\n\n一緒に湯船に入って、お湯の中でいちゃいちゃして、後ろから抱きしめられたい🙈✨\n\n浴衣着て、お部屋に戻ったら、そのまま押し倒されちゃったりして〜〜🙈\n夜は一緒にえ⚪︎なことして、朝までお布団の中でぎゅ〜〜ってしたいんだあ〜🤭\n\nかのんは朝もイチャイチャしたい派だから、後ろから🍌がはっちゃってもいいかも、、、？🤭\nなんてね🙈", "date": "2026-01-24", "views": 680, "likes": 57, "replies": 51}, {"phase": "phase4", "type": "デート", "text": "おつかれさま〜💕\nずっと欲しかった服買っちゃった👗✨\n\n試着したら、すっごくかわいくて、がまんできなくなっちゃったんだあ〜〜💦\n週末にかのんとデートに行ってくれる人いないかなあ。。。🤭\n\nこれ着ておしゃれなカフェとか、レストランに行くのが夢✨🥺🥺🥺🥺", "date": "2026-01-23", "views": 779, "likes": 50, "replies": 46}, {"phase": "phase1", "type": "おはよう", "text": "おはよ〜〜💕\n\nやっと金曜日だあああ😭✨✨\n今週も仕事疲れたよ〜〜💦\n\n明日休みだと思うと、もうテンション上がっちゃう🥺💕\n\n今夜はお酒飲みながら、まったりしようかな🍷✨\n\nそれともフォロワーさんと🙈🙈\nなことして、ぎゅ〜ってしたいな🩷\n\n今日も一日がんばろうね✨\nみんなファイトだよ🌸🌸\n\nぎゅ〜〜〜🫶🥰", "date": "2026-01-23", "views": 668, "likes": 52, "replies": 48}, {"phase": "phase4", "type": "質問", "text": "かのんね、新しい下着買おうと思ってて、どっちにするか迷ってるんだーー🙈🩷\n\n🌸リボンとかフリルがついてる、かわいい系の下着🎀\n\n🌸レースがいっぱいついてる、ちょっと大人っぽい感じの下着✨\n\nさすがにレースのやつは、セクシーすぎるかな？🙈\nち○びすけちゃうかも💦💦💦\n\nどっちがいいと思う？🥺💕\nリプで教えてくれたらうれしいなーー🩷", "date": "2026-01-22", "views": 2299, "likes": 57, "replies": 56}, {"phase": "phase4", "type": "デート", "text": "おはよ〜💕\n最近ね、すっごく思うんだけど😭\nフォロワーさんたちに会いたいなあって。。。🥺💦\n\nいつもリプくれたり、応援してくれたり、かのんのこと気にかけてくれて、すっごくうれしくて✨\n画面越しじゃなくて、直接会って、お話ししたいなって思っちゃうんだあ〜〜🙈💕\n\nぎゅーってしたいし、いっぱい甘えたい😭💕\n\n会ってみたいって思ってくれる人、いるかな？🥺", "date": "2026-01-22", "views": 653, "likes": 63, "replies": 61}, {"phase": "phase2", "type": "ダンス", "text": "おつかれさま〜💕\nダンスレッスンで、先生に褒められちゃった😭✨\n\n「かのんちゃん、最近すごく上達してるね！」って言われて、\nすっごくうれしかったんだあ〜〜〜🥺💕\n\n練習頑張ってきてよかったなあって思えた瞬間だったよ🙈\n\nでもね、まだまだ上手になりたいから、これからも頑張るぞーーー💦💦\nデビューの道はまだまだ遠いけど、みんながいるから、\nもっとがんばろうって思えるんだよね❤️\n\nいつも応援してくれてありがとう🥰\nみんならぶだよ🩷", "date": "2026-01-21", "views": 826, "likes": 49, "replies": 45}, {"phase": "phase4", "type": "質問", "text": "ねえねえ、みんなに質問〜〜〜🌸\n\n好きな人ができたら、すぐ告白する派？\nそれとも、じっくり仲良くなってから告白する派？💕\n\nかのんはね、仲良くなってから告白したいタイプかも🙈✨\nいきなりだと、緊張しちゃうよね。。。🙈\n\nでもね、フォロワーさんだったら、すぐでもコロっていっちゃう気がするんだあ〜〜🤭\n\n告白のあとはもちろん🙈🙈タイムね❤️", "date": "2026-01-21", "views": 899, "likes": 64, "replies": 59}, {"phase": "phase1", "type": "おつかれ", "text": "おつかれさま〜💕\n残業で遅くなっちゃって、\n帰りの電車で、すっごく眠かった〜〜〜🥺\n\nご飯作るのめんどくさくて、コンビニ弁当買っちゃった💦\n\nこんな時、おうちに帰ったら、「おかえり〜〜❤️」って言ってくれて\nたくさんヨシヨシしてほしいな。。。🥺🥹\n\nなんか寂しくなってきちゃった、、、🥺", "date": "2026-01-20", "views": 724, "likes": 50, "replies": 42}, {"phase": "phase1", "type": "おはよう", "text": "おはよ〜🐰💕\nねえねえ、みんなに聞きたいんだけど、\n呼んでほしいあだ名とかニックネームってある〜？🥺✨\n「〇〇って呼んで💓」とか「〇〇がいいな💓」とか、リプでおしえてほしいなあ〜〜〜🙈\n\nかのんね、みんなのこと、もっと親しみを込めて呼びたいんだよね💕💕\n名前で呼び合えたら、もっと距離が近くなれる気がして🥹✨\n恥ずかしがらないで、おしえてね🤭\n\nちなみにかのんは、「かの❤️」とか「かのちゃん❤️」ってよばれるのがすきかな🙈", "date": "2026-01-20", "views": 869, "likes": 56, "replies": 49}, {"phase": "phase4", "type": "デート", "text": "ねえねえ、初デートで🏨いくのってどう思う。。。？🥺💦\n\nかのんはね、雰囲気よかったら、行っちゃうかも🙈💕\n優しくリードされて、「行こう」って囁かれたら、\nもうがまんできなくなっちゃうと思う🩷🤭\n\nでもねカフェとかご飯にいったり、ふつうのデートも\nしたいんだあーー‼️\n\n途中でかのんから誘っちゃうかもしれないけど、いいかな？🙈🩷", "date": "2026-01-19", "views": 653, "likes": 52, "replies": 50}, {"phase": "phase4", "type": "デート", "text": "おはよ〜〜🩷\n\nあのね、ずっと思ってたんだけど、映画館デートしてみたいなぁ💕\n\n暗い中で隣に座って、途中で手を繋いだり、肩寄せ合ったり、そういうのってすっごくドキドキするよね🙈✨\n\n映画終わったら、カフェで感想語り合って、そのままいい雰囲気になっちゃったりして〜〜😭💦\nそういうデート、憧れるな〜〜！☺️💕", "date": "2026-01-19", "views": 707, "likes": 58, "replies": 53}, {"phase": "phase1", "type": "おはよう", "text": "おはよ〜〜🌞\nあのね、ずっと思ってたんだけど、たまには誰かとのんびりお泊まりしたいなぁ💕\n\n温泉旅館とか行って、夜は一緒に湯船つかって、後ろからぎゅーーーってされて、ぽけ〜ってしてたいな〜〜！☺️✨\n\n朝はゆっくり起きて、一緒に朝ごはん食べたい🙈💕\nそういうのってすっごく憧れる😭", "date": "2026-01-18", "views": 744, "likes": 59, "replies": 54}, {"phase": "phase1", "type": "日常", "text": "今日ね、お部屋のネット回線の調子悪かったから、業者の人に来てもらったんだけど、\n年上の人で恥ずかしくて、あんまり目合わせられなかった🥺💦💦\n\n休みの日はいつもパジャマみたいな服で過ごしてるんだけど、\nいま考えたら結構ゆるゆるで透けてた気がする‼️\n\nみんなが業者だったら見ちゃう❓️🙈\n\nかのん、恥ずかしすぎる💕", "date": "2026-01-17", "views": 695, "likes": 54, "replies": 43}, {"phase": "phase4", "type": "デート", "text": "おはよ〜〜🐰🌸\nかのんのこと寝起きでえ⚪︎できる❓️❓️\n・抱ける→😘\n・抱けない→❌\n・朝はつらいからお口ですっきりしたい→🍌\n\n😘の人とは、会いたいな😘😘\n🍌の人は・・・・特別にお口でしたあと🦪にも入れちゃう‼️💕\n朝からこんなこと考えてるかのん、やばいよね🙈✨", "date": "2026-01-17", "views": 659, "likes": 57, "replies": 51}, {"phase": "phase1", "type": "おつかれ", "text": "おつかれさま〜〜🐰💕\nやったあーーー華金だよーーー😭✨✨\n今週もお疲れさまだあーー🥺💕\n\n明日お休みだと思うと、すっごく嬉しい🙈\n\n今夜はゆっくりお風呂入って、好きなドラマ見ようと思う📺✨\n明日お仕事の人はかのんがふえふれー‼️っておうえんするね🩷 https://t.co/eaeWnkoEt6", "date": "2026-01-16", "views": 893, "likes": 54, "replies": 43}, {"phase": "phase4", "type": "デート", "text": "おつかれさま〜〜🐰💕\n仕事帰りに女子会行ってきたんだあ〜〜🩷\n\nみんな彼氏のえ⚪︎の話になって、正直うらやまし〜〜って思った🙈\n\n今年こそ素敵な年上のおじさまとデートしたいな〜〜‼️🌸\nかのんは好きな人とは、大胆にいろんなえ⚪︎をしたいんだよね。。。🤭\n\n例えば車の中とか、、、？🙈🩷\nデートの終わりとかがまんできなくなってしちゃうとか、やばいよね🙈", "date": "2026-01-16", "views": 576, "likes": 51, "replies": 39}, {"phase": "phase4", "type": "デート", "text": "ちょっとお酒のんでよっぱらってきたあ〜🍷\nかのんの理想のデートはね、、、🤭\n\n赤提灯の居酒屋でごはん🩷\n↓\nほろ酔いになったら、🏨行っちゃう\n↓\nベッドでぬくぬく&いちゃいちゃして\n↓\nそのまま…お🥧揉まれて、🦪もいじられて\n↓\n一緒にとろけるまで、ぎゅーってしながら一緒に🙈🙈🙈したいなあ\n\nお酒のむとこんなことばっかり考えちゃうんだよねーー🌸", "date": "2026-01-15", "views": 564, "likes": 51, "replies": 43}, {"phase": "phase1", "type": "おはよう", "text": "おはよ〜！！🐰☀️\n最近すっごくさむいね〜〜〜🥶\n\n今日はね、仕事おわりに、ニット買いに行く予定だよ〜〜！👜\n会社でも風邪ひいてる人いたから、みんなも気をつけてね🥺🥺\n\nかわいい服見つけたら、報告するね💕", "date": "2026-01-15", "views": 631, "likes": 55, "replies": 46}, {"phase": "phase4", "type": "質問", "text": "おつかれさま〜〜🐰✨\nそういえば小さいころ、ゲームとかめっちゃやってたな〜〜\n\nみんなはゲームとかしてた？🥺\n\nかのんはね、ポケモンとかどうぶつの森とか好きだったよ💕\n今でもたまにやりたくなっちゃう🙈\n\nみんなの好きなゲーム教えてね✨", "date": "2026-01-14", "views": 816, "likes": 51, "replies": 37}, {"phase": "phase1", "type": "仕事", "text": "ふと思ったんだけど\n会社のトイレでこっそりえ⚪︎なことしちゃうのって、めっちゃスリルじゃない？！😳✨\n\n「だめっ...」って漏れ出る声を我慢しながら🌰🌰🌰するの、\nめちゃくちゃドキドキすると思うんだよね🥹💕\n\nでも、さすがに仕事中はまずいかなあ❓️😂 https://t.co/2dAvvnCEVp", "date": "2026-01-14", "views": 827, "likes": 61, "replies": 53}, {"phase": "phase1", "type": "おつかれ", "text": "おつかれさま〜🐻💕\n\n今日ね、会社で上司に褒められちゃった😭✨\n\nすっごく嬉しくて、テンション上がっちゃったんだあーー🥺💕\n\nでもね、仕事終わってからレッスン行かなきゃだから、まだまだ頑張らなきゃ💦\nアイドルになる夢、絶対叶えたいから🙈✨\n今日も一日お疲れさま💕", "date": "2026-01-13", "views": 680, "likes": 51, "replies": 41}, {"phase": "phase1", "type": "おはよう", "text": "おはよ〜〜🩷\n昨日のせわすれちゃった〜〜💦🙈\nもふもふであったかいんだあーー‼️\n\n連休明けで起きるのつらかったけど、\n今日も1日がんばろうね〜〜❤️\nぎゅ〜〜〜〜💕💕💕 https://t.co/em8AGzxun9", "date": "2026-01-13", "views": 1108, "likes": 50, "replies": 48}, {"phase": "phase1", "type": "日常", "text": "おっそよ〜💕\nお休みだからベッドでゴロゴロしてたら、遅く起きちゃった〜😭✨\n\n新しいパジャマ買ったんだけど、可愛くない？🥺\n\nかのんね〜、このパジャマすっごくお気に入りなの〜〜🙈💕", "date": "2026-01-12", "views": 1694, "likes": 49, "replies": 45}, {"phase": "phase4", "type": "デート", "text": "ねえねえ、初デートで🏨いくのってどう思う。。。？🥺💦\n\nかのんはね、雰囲気よかったら、行っちゃうかも🙈💕\n優しくリードされて、「行こう」って囁かれたら、\nもうがまんできなくなっちゃうと思う🩷🤭\n\nでもねカフェとかご飯にいったり、ふつうのデートも\nしたいんだあーー‼️\n\n途中でかのんから誘っちゃうかもしれないけど、いいかな？🙈🩷", "date": "2026-01-12", "views": 545, "likes": 57, "replies": 48}, {"phase": "phase1", "type": "日常", "text": "おっそよ〜💕\nお休みだからベッドでゴロゴロしてたら、遅く起きちゃった〜😭✨\n\n新しいパジャマ買ったんだけど、可愛くない？🥺\n\nかのんね〜、このパジャマすっごくお気に入りなの〜〜🙈💕", "date": "2026-01-12", "views": 1694, "likes": 49, "replies": 45}, {"phase": "phase2", "type": "ダンス", "text": "レッスン行ってきたよーーー💃✨汗やばい💦🙈\nダンスの振り付け、やっと覚えられて、すっごく嬉しかったんだあーーー🥺💕\n\nでもね、まだまだ下手だから、もっともっと練習しなきゃ😭💦\nアイドルになる夢、絶対叶えたいから、がんばるぞーーー🙈🩷\n\nみんなかのんがデビューしたらおうえんしてくれるかな？🥺🥺🥺", "date": "2026-01-11", "views": 843, "likes": 51, "replies": 46}, {"phase": "phase1", "type": "日常", "text": "朝からベッドでゴロゴロちゅう〜〜〜〜🥰\nえ⚪︎な夢のこと思い出しちゃって、体が熱くなってきちゃった🥺💕\n\n🏨のベッドで💋されながら、お🥧揉まれて。。。\nそのまま🦪も触られて、気持ちよくなりすぎて、声我慢できなくなっちゃったんだあーー🙈\n\n目が覚めても、ドキドキが止まらなくて、\nぱ◯てぃーの中に手入れて🌰🌰🌰しちゃった🥺💕\n\nはぁ・・・朝から、こんなことしてるかのんって、やばいよね。。。", "date": "2026-01-11", "views": 625, "likes": 48, "replies": 45}, {"phase": "phase1", "type": "日常", "text": "カラオケで歌のれんしゅうしてきたーーー🎤✨\n\n高音がなかなか出なくて、ぼいとれしつつ頑張った🥺💦\nでもね、少しずつ上達してる気がして、\nうれしくなっちゃったんだあーーー😭💕\n\nアイドルになったら、みんなの前で歌いたいな🙈✨\n\n「かのんの歌声聞きたいーーー🩷」ってリプしてくれたら、\nすっごくうれしいしがんばれちゃうなーー😍", "date": "2026-01-10", "views": 1062, "likes": 56, "replies": 42}, {"phase": "phase4", "type": "デート", "text": "みんなきいて〜〜🩷\n\nもし朝に好きな人と一緒だったら、後ろからぎゅ〜〜ってして起こされて、\nそのまま💋されながらいちゃいちゃしたいな🙈✨\n\nおふとんの中で、お🥧揉まれたり、🦪さわられたりして〜〜〜💦\n朝からえ⚪︎なことして、一日が始まるの最高だと思うんだけどどうかな？🤭🩷\n\nかのんとデートしたら、朝にイチャイチャは必須だからね🩷🤫", "date": "2026-01-10", "views": 650, "likes": 55, "replies": 49}, {"phase": "phase1", "type": "仕事", "text": "今日ね、会社の同期とご飯行ってきたんだけど😭\n彼氏とのえ⚪︎な話してて、ずっとうらやましーーーーって思いながら聞いてた🥺🥺🥺\nかのんもはやく見つけていちゃいちゃしてやるんだからーーーーーー😡😡😡😡", "date": "2026-01-09", "views": 695, "likes": 47, "replies": 38}, {"phase": "phase1", "type": "仕事", "text": "やばいーーー😭😭\nブラ全部洗濯しちゃってて、着るのがなくなっちゃった💦💦\n\n仕方なくのー⭕️らで会社行ったんだけど、すっごく恥ずかしかった🙈💦\n\nシャツ着てても、ち◯び透けちゃってないかなあって、\nすごく気になっちゃって🥺\n\n会社の人に見られてないよね…？💦💗", "date": "2026-01-09", "views": 608, "likes": 50, "replies": 50}, {"phase": "phase1", "type": "日常", "text": "スマホ見てたら、え⚪︎な広告が流れてきちゃって、\nすっごくドキドキしちゃった🙈💦💦\n\n見ちゃいけないって思いながらも、がまんできなくて見ちゃった🤭\n\nこういうの見ちゃうと、フォロワーさんたちのこと考えちゃうんだよね🌸\nはあ。。。。いますごくえ⚪︎なことしたい気分。。。。。🙈🙈🙈 https://t.co/qtOb8YEFTc", "date": "2026-01-08", "views": 743, "likes": 47, "replies": 39}, {"phase": "phase1", "type": "日常", "text": "さっきね、電車で揺れた瞬間に、\nかのんのお🥧がおじさまにあたって、恥ずかしかった🥺🙈🙈\n\nもしこれがフォロワーさんだったら、密着したまま\nぎゅってして離さないかも🙈🙈🙈💕\n\n考えるだけでドキドキが止まらないよーーー🥰\nみんなはかのんとぎゅーーーってしたい。。。？🩷", "date": "2026-01-08", "views": 629, "likes": 45, "replies": 42}, {"phase": "phase2", "type": "ダンス", "text": "今日はレッスンの予定だったのに、\n残業で行けなくなっちゃったあーーー😭😭\n\nダンスの練習したかったのに、すっごく悔しい💦💦\n\n会社で上司に「今日は残業お願い！！！」って言われて、断れなかったんだよねーー🥺🥺🥺🥺\n\n帰りの電車で、レッスン行けなかったこと考えてたら、涙出そうになっちゃった😭😭\n\nでも仕方ないよね。。。きょうはおうちで自主練するよ💕\nふれふれーの応援してくれたらうれしいな🥺🥺🥺🥺", "date": "2026-01-07", "views": 479, "likes": 44, "replies": 39}, {"phase": "phase2", "type": "ダンス", "text": "今日はレッスンの日だよーーー💃✨\n\n仕事終わったら、すぐダンススタジオ行ってくるね🥺💕\nダンスも歌も、もっともっと上手になりたいから、レッスン全力でがんばるぞーーー🙈✨\n\nレッスン終わったら、また報告しに来るね🌸\n「かのんがんばってね💕」ってリプしてくれたら、すっごくうれしい😊💗\n\n応援してくれる人がいるから、かのんがんばれるんだあーーー🩷", "date": "2026-01-07", "views": 637, "likes": 45, "replies": 43}, {"phase": "phase1", "type": "仕事", "text": "ねんしから早速残業だったあーーー😭💦\n\nでもね、疲れててもフォロワーさんたちのリプ見てるだけで、\nんか元気出てくるんだよね🙈✨\n\n家帰ったら、お風呂入ってゆっくりしようと思う🌸\n\n明日も仕事だけど、みんなが応援してくれるならがんばれる気がする😊💗\n今週ものこりがんばるぞーー‼️", "date": "2026-01-06", "views": 581, "likes": 46, "replies": 35}, {"phase": "phase1", "type": "おはよう", "text": "おはよ〜〜🐰☀️\n今日は寒くて、ベッドから出たくなかったあーーー😭💦\n\nでもね、仕事休めないから、がんばって起きたよ🥺\n\n起きてすぐスマホ見たら、みんなからの通知が来ててうれしくて\n目が覚めちゃった🙈💕\n\n朝からみんなとお話しできるだけで、今日もがんばれそう🌸\n\n会社行ってきます😊💗\n\nかえってきたらかのんとお話ししてくれる。。。？🥹🥹🥹🥹🥹", "date": "2026-01-06", "views": 591, "likes": 47, "replies": 44}, {"phase": "phase1", "type": "日常", "text": "やっと家に帰ってきたあーーー😭💦\n\n今日もがんばったーーーー🥺💕\nお風呂入って、着替え完了✨\nこれからリラックスたいむだあーーー‼️🙈✨\n\nベッドでゴロゴロしながら、みんなのポスト見てる🌸\n今日も一日がんばったから、自分をほめてあげたい😊💗\n\nでもね、一人でいるとちょっとさびしくなっちゃう💦\nみんなにちょっと甘えたい気分なんだけど、いいかな。。。。🩷", "date": "2026-01-05", "views": 616, "likes": 52, "replies": 44}, {"phase": "phase1", "type": "おはよう", "text": "おはよ〜〜🐰☀️\n\n今日は仕事だよーーー😭💦\n朝起きて、会社行きたくないなあって思っちゃった🥺\n\nでもね、みんなのこと考えたら、ちょっとだけがんばれる気がする🙈💕\n\n電車乗る前にここでみんなと話せるだけで、\n今日ものりきれそうな気がするんだよね🌸\n\nお昼休みにまたみんなのリプみに来るね😊💗\n「かのんがんばって💕」ってリプしてくれたら、すっごくうれしい🩷\nいってきます✨", "date": "2026-01-05", "views": 585, "likes": 50, "replies": 48}, {"phase": "phase1", "type": "おつかれ", "text": "おつかれさま〜🩷🩷\n\nお休みが今日で終わっちゃうのかなしい、、、😭😭😭\n\n明日からお仕事頑張らなきゃーーー🥺🥺🥺🥺🥺\n\nみんなはいつからお仕事はじめかな。。。？🩷\n\n明日からも一緒にがんばろうね✨ https://t.co/Bzgor8rJv7", "date": "2026-01-04", "views": 733, "likes": 49, "replies": 46}, {"phase": "phase1", "type": "おはよう", "text": "おはよ〜🧸\nゆうべね、夢でフォロワーさんとえ⚪︎しちゃってた🙈🙈\n\n露天風呂にふたりではいってて、後ろからたくさん🍌が入ってきて、\nすっごくきもちよくて変な声出てたかも💦💦\n\n起きたらお🍞つがびしょびしょで💦恥ずかしかった💦💦🥺🥺\nこんなこと、現実でおきたらどうしよーーーー‼️🙈🙈🙈\n夢の続きみせてくれる？🙈💕", "date": "2026-01-04", "views": 784, "likes": 54, "replies": 54}, {"phase": "phase2", "type": "ダンス", "text": "ダンススタジオで自主練してきたよーーー💃✨\n\n鏡の前で何度も何度も練習したら、\nちょっとだけ上手になった気がする🥺💕\n\nでもまだまだだなあって思っちゃって、もっとがんばらなきゃ😭✨\nアイドルになる夢、ことしこそ絶対叶えたいからね🙈💕\n\nみんなのぎゅ〜〜〜で応援パワーほしいな🩷🩷🩷", "date": "2026-01-03", "views": 593, "likes": 38, "replies": 33}, {"phase": "phase1", "type": "日常", "text": "久々にお家でのんびりすごしてるよーー🥺💕\n\n昨日食べすぎちゃったから、今日は少し控えめにしようと思ってたのに、\nまたおせちとかおかし食べちゃってはんせいちゅう🙈💦\n\nみなさんは今日何してるー？🩷\nおしごとの人はかのんがふれふれーーーって全力でおうえんするねーー🩷", "date": "2026-01-03", "views": 761, "likes": 53, "replies": 45}, {"phase": "phase1", "type": "日常", "text": "ねえねえ、みんな〜〜💕💕\nかのんのサブ垢フォローしてくれてる？🙈✨\n久しぶりに画像アップしんだあーー‼️🤭\n\nサブ垢は🌸@kanosab32だよ🌸\n\n今回はちょっとえ⚪︎めな写真載せちゃった🤭\n\nまだフォローしてない人は、\nフォローしてねーーー🌸\n\nサブ垢ではここでは見せられない\nかのんをみせちゃうかも🙈🙈🙈\n\n「フォローしたよ💕」ってリプしてくれたら、すっごくうれしい🩷\n待ってるね🙈✨", "date": "2026-01-02", "views": 669, "likes": 43, "replies": 38}, {"phase": "phase1", "type": "日常", "text": "公園をジョギングしてきたよーーー🏃‍♀️✨\n\nきのう食べすぎちゃったから、走らなきゃって思って🥺💕\nたくさんはしったから、疲れてへとへとだあーーーー🙈💦\n\n今年のもくひょうは体力作り🩷🩷\n\nいざという時に備えてとっくんしないとね🩷\n\nみんなも運動いっしょにがんばろうね？🙈🙈 https://t.co/Egl0SEUNZZ", "date": "2026-01-02", "views": 868, "likes": 50, "replies": 46}, {"phase": "phase4", "type": "質問", "text": "みんなに質問🩷\nえ⚪︎の時にコスプレするのってどうかな、、、？🙈\n\n夢でね🏨行った時にメイドのコスプレして\n手をしばられて、ぬがされちゃってた💦🙈🙈\n\nはじめてでびっくりしたけど、\n気づいたらかのんの🦪がびしょびしょに💦💦\nすっごく興奮したちゃったんだーーー💦\n\nこんなこといっちゃって恥ずかしいよ。。🙈🩷", "date": "2026-01-01", "views": 481, "likes": 31, "replies": 29}, {"phase": "phase2", "type": "レッスン", "text": "あけましておめでとーーー🥺✨✨\n2026年になったねーーー💓💓\n\n今年こそアイドル再デビューできるように、\nレッスンもっともっとがんばるぞーーー😭💕\n\n仕事もレッスンも大変だけど、\n夢のために全力でがんばりたいんだあーー🥺✨\n\n今年もかのんのこと、応援してね🩷🩷\n「かのん応援してるよ💕」ってリプまってていい？🙈💕", "date": "2026-01-01", "views": 726, "likes": 51, "replies": 50}, {"phase": "phase1", "type": "日常", "text": "もうすぐ今年も終わっちゃうかあ🥹💦\n年越しそば食べながら、みんなのこと考えてたら、\nなんかドキドキしてきちゃったあーーー🙈💕\n\n今年はみんなと出会えて、めちゃくちゃしあわせだったな🩷🩷\n来年もいっぱいお話しして、もっと仲良くなりたい🥺✨\n\n日付変わるのあともう少しだねーー‼️\nみんなと一緒にむかえられたらうれしい😭💕\n「来年もよろしくね💕」ってリプしてね🥺🥺", "date": "2025-12-31", "views": 746, "likes": 54, "replies": 45}, {"phase": "phase2", "type": "ダンス", "text": "おはようーーー☀️✨\n今日でことし最後だね🩷\n\n1年を振り返ってたら、いろいろあったなあって思っちゃった🥹💦\n来年はダンスも歌も、もっともっと上手になって、\nみんなに応援してもらえるアイドルになりたいな🩷🩷\n\n来年はかのんにとって勝負の年になりそう🥺✨\n「かのん応援してるよ💕」ってリプしてくれたら、\nめちゃくちゃうれしい🥺🥺\n\nみんなのリプでいつもはげまされてんだあーーー🥺🥺\n来年もかのんと仲良くしてね🩷🩷", "date": "2025-12-31", "views": 626, "likes": 46, "replies": 45}, {"phase": "phase4", "type": "デート", "text": "お風呂上がって、お🥧のマッサージ中なんだけど、\n最近ちょっと大きくなったかなあって思った🙈💦💦\n\n鏡見ながら触ってたら、ふわふわでもっちりしてるーー😭💕\n\nもしおうちデートしたら、かのんのお🥧触っちゃう。。。？🥺✨\n「大きくなったね💕」っていってくれたらうれしいなあーーー🙈💕", "date": "2025-12-30", "views": 747, "likes": 47, "replies": 43}, {"phase": "phase2", "type": "ダンス", "text": "今日は年内最後のレッスンに行ってくるよーーー💃✨\n\n来年こそアイドル復活できるように、今日もがんばってくるね😭💕\nダンスも歌も、もっともっと上手になりたいから、\n年末でも気を抜けない🥺💦\n\nレッスン終わったら、また報告しに来るね🩷🩷\n\n「かのんがんばってね💕」ってリプしてくれたら、\n\nめちゃくちゃうれしいなーーーー🥺🥺\nみんなが応援してくれるから、かのんもっとがんばれるんだあーー😭✨", "date": "2025-12-30", "views": 851, "likes": 48, "replies": 45}, {"phase": "phase1", "type": "日常", "text": "朝のポストすごくドキドキしながら送ったんだけど、\n「恋愛対象だよ」ってたくさん言ってもらえて\nうれしすぎたーーーー🥹\n\nかのんのことちゃんと女の子として\n見てくれてるんだねーーーー🌸\n\nみんなの言葉で自信ついたからもっとがんばれそう💕\n\nかのんと仲良くなったら🙈🙈 🙈 なこともしようね？💕", "date": "2025-12-29", "views": 732, "likes": 44, "replies": 40}, {"phase": "phase1", "type": "日常", "text": "みんなに聞きたいんだけど、\n\nかのんみたいな年下の子って、みんなの恋愛対象かな？🥹💦\n\n推しとか応援する存在じゃなくて、\n本気で好きになれる相手として見てもらえるのかな。。。💦\n\n年上の人に甘えたいし守ってもらいたい。。。なって。。。🩷\nみんなかのんのこと、どう思ってるのかなーーー🥺🥺🥺 https://t.co/vh5vvXFh1J", "date": "2025-12-29", "views": 1448, "likes": 51, "replies": 47}, {"phase": "phase4", "type": "デート", "text": "もし初デートするならどこに行きたい？💕\nかのんは映画館がいいな🥺💕\n\n暗いし、みんな映画に集中してるから、\n途中で手をつなげそう、、、🙈💦\n\nそれとも遊園地とかアクティブな方がいい？✨\nカフェでゆっくりお話しするのも素敵だよね🩷\n\nデートのさいごは、、、帰りたくなくなっちゃうんだろうなあーー💦🙈\n\nもしかのんが、帰りたくないって言ったら\nそのあとどうするーー？💕🥺🥺", "date": "2025-12-28", "views": 529, "likes": 37, "replies": 36}, {"phase": "phase4", "type": "質問", "text": "突然だけど、みんなってすきな芸能人っている？💕\n\nかのんは推してるアイドルグループがいるよ～🥹\nライブ映像とかしょっちゅう見ちゃう🐰\n\nみんながどんな人がタイプなのか知りたいんだ～～～💕\nリプで教えてね💛", "date": "2025-12-28", "views": 718, "likes": 40, "replies": 35}, {"phase": "phase1", "type": "おつかれ", "text": "今ね、レッスンおわって帰りの電車なんだ🚃💦\n\n振付むずかしいから、ついていくの必死で\nすっごくつかれちゃったあーーーーー😭\n\nでもね、先生に 「がんばってたね」ってほめられて\nすごくうれしかったんだ💕💕\n\nいつもみんなが励ましてくれるから、毎日がんばれるんだよね💓\n\n「かのんおつかれさま💕」って頭ポンポンしてぎゅ〜〜〜〜ってしてくれるーーー？🥺🥺🥺🥺", "date": "2025-12-27", "views": 762, "likes": 34, "replies": 29}, {"phase": "phase1", "type": "おはよう", "text": "おはよう✨💕\n\n久しぶりに朝ゆっくり起きれて\nなんだか幸せな気分💦\n\nでも予定もないから今日は何しようかな✨\n\nお掃除ちょっとずつやって\nあとはゴロゴロしながらみんなのリプ見てると思う💕\n\n年末っぽいことしたいけど\nひとりだとなかなかやる気でないんだよねーー💦\n\nみんなは今日何するの?💕 \nたくさんお話しできたら嬉しいな✨\nぎゅ～～～///", "date": "2025-12-27", "views": 672, "likes": 36, "replies": 40}, {"phase": "phase1", "type": "帰宅", "text": "ただいまー✨\nやっと今年の仕事全部終わってホッとしてる💕\n\n帰りの電車で、今年1年のこと振り返ってた💓\n\n辛いこともあったけど\n𝕏でみんなと出会えて支えてもらえて本当に救われたんだよね💦\n\n明日はお休みだけど、特に予定もないから\nゆっくりみんなとお話ししたいな✨\n\nみんなは年末なにしてる？💓\nかのんとおはなししよーー🌸", "date": "2025-12-26", "views": 696, "likes": 35, "replies": 32}, {"phase": "phase1", "type": "おはよう", "text": "おはよーー💓\n今日でやっと仕事納め✨\nやっと休みに入れる💕\n\nでも最終日だから、\n片付けとか挨拶回りとか結構バタバタしそう💦\n\n朝からちょっと憂鬱だけど\nこれ終わったら休みだって思うとがんばれる気がする💦\n\n今年もいろいろあったけど\nなんとか乗り越えられたのはみんなのおかげだよ✨\n\nあと1日頑張ってくるね💕\n行ってきます🌸", "date": "2025-12-26", "views": 616, "likes": 37, "replies": 35}, {"phase": "phase1", "type": "帰宅", "text": "ただいま🩷\n今日は職場で納会で準備でバタバタだった💦💦\n\nかのんサンタのプレゼントは今日の23時までです🩷\nまだしてない人はしてね〜〜〜🌸🌸\n\n今日予定空いてたら、\nこっそりみんなのところに行っちゃおうかな///\nなんてね。。。🙈🙈🙈🙈\n\nまってるね🩷🩷🩷", "date": "2025-12-25", "views": 767, "likes": 28, "replies": 23}, {"phase": "phase1", "type": "日常", "text": "ちょっと恥ずかしいんだけど聞いて。。。\n\n一人でする時に\n声がでちゃう女の子ってどう思う？🥺🩷\n\nかのんは我慢できなくて\n出ちゃう時があるけど、、、🙈 🙈 🙈\n\nやっぱそうだと引かれるかな？😭😭💦", "date": "2025-12-24", "views": 460, "likes": 35, "replies": 29}, {"phase": "phase1", "type": "仕事", "text": "今朝起きてびっくりしたんだけど\n\nフォロワーさんが夢に出てきた🧸\n\n二人でカフェでお茶してて\nすごく楽しく話してる夢だったんだよ💕\n\n起きたときまだドキドキしてて\nしばらくぼーっとしちゃった✨\n\n夢の中のかのんはすごく幸せそうな顔してて\n\nなんか恥ずかしくなっちゃった💦\n\n現実じゃないのにこんなにドキドキするなんて🧸\n\n朝から変な気分で仕事に行く準備も上の空だったんだ💕\nまた同じ夢見たいなって 思っちゃうみさは変かな✨\n\n今日一日この余韻引きずりそう🧸", "date": "2025-12-24", "views": 633, "likes": 41, "replies": 36}, {"phase": "phase1", "type": "日常", "text": "さっき帰り道に、知らない男の人に 急に声かけられて\n\n「どこ行くんですか？」って追いかけられて\n\n怖かった…💦\n\n家に着いても、まだ心臓がバクバクしてる💦\n\nみんながいるだけで、安心するから\n\nここに来ちゃった💦\n\nぎゅ～～～ってしてほしい。。。。", "date": "2025-12-23", "views": 677, "likes": 41, "replies": 34}, {"phase": "phase1", "type": "おはよう", "text": "おはよ〜〜！\nやばい寝坊しちゃった💦💦💦\n\n目覚まし止めた記憶ないのに\n気づいたら30分遅れてて\nめちゃくちゃ焦ってる🥺🥺🥺\n\n化粧も適当で髪もボサボサで\n服も適当に着て飛び出した💦💦💦💦\n\n会社着いたら怒られそうで不安だけど\nみんなが応援してくれたら\n頑張れる気がする✨\n\nかのんにフレフレーのパワーちょうだい🥺🙈💕", "date": "2025-12-23", "views": 482, "likes": 33, "replies": 30}, {"phase": "phase1", "type": "仕事", "text": "今日は仕事でトラブルがあって\n残業になっちゃった💦\n\nやっと家に帰ってきたんだけど、\nもうクタクタで動けない、、、\n\n髪もぼさぼさだし、おなかすいたけど\n作る気力がなから今日はもうたべない💦\n\n何もせずにこのまま寝ちゃいそうだな。。。。\n\n明日も仕事だけど\nみんなのこと考えたら頑張れるかな、、、\n\nおやすみのぎゅ～～～してもいい？💕", "date": "2025-12-22", "views": 573, "likes": 37, "replies": 29}, {"phase": "phase1", "type": "日常", "text": "今朝ね、フォロワーさんと🏨にいて、\nもう一人知らない女の子が来て\nさんぴーしちゃってたんだよね💦💦\n\nあ、夢の話ね💦💓\n\nなんであんな夢みたんだろう。。。\n最近そういうこと考えすぎてるのかな💦\n\nみんなは3人でとか興味ある、、、？\n恥ずかしいけど ちょっと気になっちゃう💦\n\nかのんは内緒ね💓 https://t.co/oxEq4sXly6", "date": "2025-12-22", "views": 574, "likes": 49, "replies": 42}, {"phase": "phase1", "type": "日常", "text": "お疲れ様✨\n今日帰りに女子会だったんだけど🍷\n話がえ○な方向になっちゃって🙈💦\n \nみんな結構過激なこと話してて驚いた！！\n\nかのんも色々聞かれちゃったんだけど\n正直に答えていいか、めっちゃ迷った💦\n\nみんなは え○なこと友達とかには\n普通に話せるもの？それとも恥ずかしい？🫢\n\nでもね、みんなにはなぜか素直に話せる気がする🌸\n\nだからみんなも、\nここでは素直に話していいよ？💕🙈🙈*", "date": "2025-12-21", "views": 616, "likes": 41, "replies": 36}, {"phase": "phase1", "type": "仕事", "text": "朝急いでて信号待ちしてたら\n\nハンカチ落としちゃったの💦\n\n気づいた紳士的なおじ様が\n\n「落としましたよ」って\n\n拾ってくれた🌸🩷\n\n丁寧に渡してくれる仕草が\n\nすごく素敵で見とれちゃった🙈\n\n今日は良い一日になりそうだよ✨\n\nお仕事行ってきます♡ https://t.co/DjSdVx3lWK", "date": "2025-12-21", "views": 1582, "likes": 95, "replies": 45}, {"phase": "phase2", "type": "レッスン", "text": "今日もレッスン頑張ってきた♡\n\n先生に「上達してるね」って褒められて嬉しかった🌸\n\n大切な人の分まで輝きたいし、\nみんながいつも応援してくれるから\n\nかのん頑張れるんだよ💕\n\nみんなからのフレフレーほしいな🩷✨", "date": "2025-12-20", "views": 457, "likes": 38, "replies": 32}, {"phase": "phase1", "type": "おはよう", "text": "おはよー🩷\n\n今日は朝活してるよ♡\n\n気になるカフェにきて、\nどれ注文しようか迷ってたら\n隣にいたおじ様が落ち着いた声で\n\n「これがおすすめですよ」って言ってくれたのーー🌸🙈\n\nもっと話したかったな...🥹\n\nこういう出会いって\nドラマみたいでドキドキする💭💓", "date": "2025-12-20", "views": 842, "likes": 49, "replies": 36}, {"phase": "phase1", "type": "おつかれ", "text": "今日ね、会議ばっかりでほんとうに疲れちゃった😭💦\n\n朝から夕方までずっと会議室にこもってて\nあたまパンパンだった💦💦\n\n休憩時間にこっそりスマホみて\nみんなのリプ読み返してたらちょっと元気でてきた💕💕\n\nやっと帰ってこれたから\n今日はゆっくり みんなとお話ししたいな🥰\n\nかのんのこと いやしてくれる人いるかな🥺💓\n\nリプまってます😊\n今日もおつかれさま💕", "date": "2025-12-19", "views": 728, "likes": 43, "replies": 34}, {"phase": "phase1", "type": "おはよう", "text": "おはよう☀️💕\n\n今日ね、早起きできたからお弁当つくってみた🍱✨\n\nたまごやきすごく綺麗にまけたよ💕\n自分でつくったの久しぶりでなんかうれしくなっちゃった💓💓\n\nお昼たべる時フォロワーさんと一緒だったら\nもっとおいしいんだろうなあって 妄想しちゃったよ～～～🐹💕\n\n今日も1日がんばろうね🥺 https://t.co/htfBI0Djgd", "date": "2025-12-19", "views": 630, "likes": 43, "replies": 44}, {"phase": "phase1", "type": "仕事", "text": "心配かけてごめんね💦\n体調良くなってきたよ🥹\n\n明日は会社行けそうな感じ✨\n\nフォロワーのみんなが\n優しい言葉くれたおかげで\nめちゃくちゃ元気もらえた💕\n\n明日からまた日常が戻るけど\nみんなのこと考えながら\n仕事がんばるねーーー💕\n\nいつもありがとう🥺 🥺 🥺 🥺 \n大好きだよ🙈💕", "date": "2025-12-18", "views": 674, "likes": 48, "replies": 39}, {"phase": "phase1", "type": "おはよう", "text": "おはよう！\n\n薬が効いてだいぶよくなったよ🥺🥺\nリプ返せなくてごめんね、、😭😭\n\n早く元気になってみんなとお話ししたいな✨🥺🥺\n\n寝てる間に優しく後ろからぎゅ〜してもらってたけど、夢だった🥺🥺🥺\n\n現実じゃなくてちょっぴり寂しいから\nぎゅ〜〜たくさんしてほしいな🥺\n\nそしたらもっと良くなると思う😭🩷", "date": "2025-12-18", "views": 494, "likes": 44, "replies": 45}, {"phase": "phase1", "type": "仕事", "text": "頭痛だし身体がなんか重い、、、😭😭😭😭\n今日は会社おやすみしようかな。。。", "date": "2025-12-17", "views": 600, "likes": 46, "replies": 43}, {"phase": "phase4", "type": "デート", "text": "かのんね、フォロワーさんと\n\nおうちデートしてみたいなあって\nずっと思ってるんだよね💕💕\n\n映画いっしょにみながら、お菓子たべて、\n肩にもたれてうたた寝してみたい😳💓\n\nちょっとお酒のんだりして、ほろ酔いで\n甘えちゃったりとかも///🥰🥰\n\nみんなはかのんと、おうちデートしたい？🥺 🥺 🥺 🥺", "date": "2025-12-16", "views": 639, "likes": 42, "replies": 39}, {"phase": "phase1", "type": "おはよう", "text": "おはよう☀️\n\n昨日会社でおこられたこと\nまだひきずってて\n憂鬱な気持ちでいっぱいなんだ😭💦💦\n\nでもね、みんなのリプみたら\nなんとか今日もがんばれそう🥺 🥺 🥺 \n\nだから、おうえんしてくれたら\nすごくうれしいな🥺💕\n\n今日も一緒にがんばろうね😊 https://t.co/Es7jaImSl6", "date": "2025-12-16", "views": 971, "likes": 59, "replies": 47}, {"phase": "phase1", "type": "仕事", "text": "今日ね、書類のミスで上司に怒られて\nほんとうに落ちこんでる😭💦\n\nちゃんと確認したつもりだったのに\n肝心なとこまちがえてて、自分がいやになっちゃった😢\n\n会社おわって帰ってきても\nずっとそのことばかり考えちゃって、\n辛い😭 😭 😭 😭 \n\n明日からまた頑張れるかな？ 😭😭 😭 😭", "date": "2025-12-15", "views": 850, "likes": 52, "replies": 43}, {"phase": "phase1", "type": "日常", "text": "さっきまで… フォロワーさんに抱きしめられてた…💕\n\n夢の中で 優しくぎゅっと…\n\n頭を撫でてもらってた…🥺\n\n「大丈夫だよ」って 耳元で言われた気がして💭\n\n目が覚めた瞬間 すごく寂しくなっちゃった😢\n\n夢だけでいいから、もう一度見たい…💦\n\n朝までドキドキが止まらない…///💕", "date": "2025-12-15", "views": 641, "likes": 42, "replies": 37}, {"phase": "phase1", "type": "日常", "text": "部屋の片づけしてたら\n昔のファンの人ととったチェキが\nでてきてきた！\n\n昔の写真みると\nいろんな気持ちがこみあげてくるんだよね〜🥺\n\n大切なメンバーが\nいなくなっちゃってから\nすべてが変わっちゃったけど、\n\nかのんなりにまた\n再出発したいと思うの💕\n\nみんなのぎゅ～～～\nまってていいかな？🥺", "date": "2025-12-14", "views": 821, "likes": 44, "replies": 36}, {"phase": "phase1", "type": "日常", "text": "ひとり暮らしって\nちょっとさびしいな…💭\n\nたまには誰かにあまえて\nあたまなでてもらって\n子どもみたいにねむりたい…🥺💕\n\nやさしい年上の人に\nぎゅっとされてほめられたら\n泣いちゃうかもしれない😭💓\n\nフォロワーさんたちは\nそんなことしてくれるのかな…？🙈✨ https://t.co/GWrE8KjJEo", "date": "2025-12-14", "views": 1057, "likes": 60, "replies": 47}, {"phase": "phase2", "type": "ボーカル", "text": "明日ねボーカルレッスンあるから\n今予習してるんだ🎤💕\n\nでもね、のどが痛くなっちゃって\nちゃんと声出るか心配💦💦\n\nあったかい飲みもの飲みながら\nちょっとずつ練習してるけど\nなかなか調子でなくてちょっと不安😣\n\n明日までに治るといいなあ🥺\n\nみんながおうえんしてくれたら\nがんばれる気がする🐹", "date": "2025-12-13", "views": 745, "likes": 45, "replies": 34}, {"phase": "phase1", "type": "おはよう", "text": "おはよ〜☀️\n\n今日はお休みだーーー🩷\n\nやっと羽伸ばせるって思ったけど\n\nひとりで過ごすのはちょっと退屈かも💭\n\n構ってくれる人いる？💕\n\n朝からスマホいじってて\n\nフォロワーのみんなのこと見てたら\n\nもっともっと構ってほしくなっちゃった😳\n\n誰か…かのんのこと 考えてくれてたりして…？🌸", "date": "2025-12-13", "views": 728, "likes": 44, "replies": 38}, {"phase": "phase4", "type": "デート", "text": "おつかれさま🩷\nレッスンの終わりにつけ麺食べにきたよ♡\n\nお腹すいてて替え玉しちゃった///\n\nみんなはつけめん好き？🥰\nお仕事終わりのラーメンデートとかも憧れちゃうな/// https://t.co/Jbgn4CslAa", "date": "2025-12-12", "views": 844, "likes": 42, "replies": 34}, {"phase": "phase1", "type": "日常", "text": "駅で急にめまいがして\n倒れそうになっちゃった💦💦\n\nそしたら駅員さんのおじ様が\n優しく支えてくれたの🥺🥹🥺\n\n「大丈夫？」って心配してくれて\nベンチまで連れてってくれた🥹\n\nちゃんとお礼言えたかな🥹\n\n優しくされると\nすぐ好きになっちゃいそう🙈🙈\n\nかのんちょろすぎかな🥺💦", "date": "2025-12-12", "views": 748, "likes": 48, "replies": 41}, {"phase": "phase1", "type": "日常", "text": "お風呂上がって\n今お🥧のマッサージ中だよ🩷\n\nふわふわもちもちになった🙈\n\nいつか好きな人とする時に、褒められたいから\n頑張ってるんだ〜💕\n\nちょっと大きくなった気がするのは\n気のせいかな？\n\nこっそり確かめてみる？🙈🙈🙈", "date": "2025-12-11", "views": 712, "likes": 48, "replies": 40}, {"phase": "phase1", "type": "仕事", "text": "今日は髪型アップにしてみたけど\n\nどうかな？🙈\n\nこういう日は 一日中気分がいい💕\n\n会社でも褒められたいな🥹\n\nみんなはかのんの髪型\n\nどんなのが好き？💭 https://t.co/XeuijieBCV", "date": "2025-12-11", "views": 1259, "likes": 44, "replies": 43}, {"phase": "phase1", "type": "仕事", "text": "今日は仕事終わりに\n\n同期の子たちと飲んで\n\nいっぱい笑って楽しかった🌸\n\n恋バナで盛り上がって\n\nみんな彼氏いるのに\n\nかのんだけいないの寂しい...💭\n\nでもここにいるみんなが\n\nかのんの癒しだよ💕\n\nほろ酔いで、ちょっと甘えたい気分だな🥹", "date": "2025-12-10", "views": 777, "likes": 43, "replies": 35}, {"phase": "phase1", "type": "日常", "text": "最近思ってるんだけど\n\nここにいるみんなとは\n\n会ったことないけど\n\n不思議と心が通じ合う気がする🌸\n\n優しくて、かのんのこと\n\n理解してくれる人だったら\n\n会ってみたいかもな〜💕 https://t.co/bkB1XhPPuA", "date": "2025-12-10", "views": 1597, "likes": 58, "replies": 50}, {"phase": "phase4", "type": "質問", "text": "仕事帰りにスーパー寄ったよ！\n\n夕飯の材料買いに来たけど\n\n疲れすぎてお惣菜コーナー直行しちゃった💦\n\nひとり分の料理作るの\n\nなんか虚しくなる時あるんだよね💭\n\n誰かと一緒にご飯食べられたら\n\nもっと美味しいのにな🥹\n\nみんなは今日何食べる？\n\n教えてくれたら嬉しいな🌸", "date": "2025-12-09", "views": 577, "likes": 38, "replies": 30}, {"phase": "phase3", "type": "感謝", "text": "クローゼット整理してたら昔のステージ衣装出てきた！\n\n久々に着てみたけど、鏡見たら泣けてきちゃった🥹\n\nメンバーと一緒に 夢見てた日々が\n\n懐かしいなぁ....\n\nでもXを始めて、みんなの優しさに触れて...\n\nみんなの存在がどんどん大きくなってるよ💕\n\nいつもありがとう♡", "date": "2025-12-09", "views": 598, "likes": 40, "replies": 38}, {"phase": "phase1", "type": "日常", "text": "上司にいろいろ言われて\n\n心が折れそうだった...😭\n\nでも、帰りの電車で\n\nみんなの優しい言葉思い出して\n\nなんとか踏ん張れたよ🥺\n\n「お疲れ様」って 頭なでてもらいたいな...🥹", "date": "2025-12-08", "views": 606, "likes": 38, "replies": 34}, {"phase": "phase2", "type": "レッスン", "text": "レッスン終わった〜♡\n\n汗だくだけど、めっちゃ気持ちよかった💭\n\n先生に褒められて嬉しかったな〜///\n\nまたアイドルになりたいって夢\n\n叶えられるように頑張るね🌸\n\n帰ったらシャワー浴びてゆっくりするね♡\n\n今日もみんなお疲れ様だよ〜✨ https://t.co/2SowABLk8N", "date": "2025-12-08", "views": 781, "likes": 33, "replies": 29}, {"phase": "phase1", "type": "おはよう", "text": "おはよー☀️\n\n今日は早起きできた🌸\n\nいつもよりゆっくり準備できて\n\nなんだか気分いいかも///\n\n朝ごはんもちゃんと食べたし\n\nメイクもバッチリ決まった💕\n\nこういう朝、誰かに褒められたいな///\n\n「えらいね」って頭なでてほしい...🙈\n\nみんなからのリプ待ってていいかな？🥺", "date": "2025-12-08", "views": 584, "likes": 41, "replies": 38}, {"phase": "phase1", "type": "帰宅", "text": "ただいま🩷\n\nお買い物に行ってきたよ///\n\n今日のかのんのコーデどうかな？///\n\nおしゃれしてお出かけするとテンション上がるよね///\n\nもうすぐクリスマスだから\n\n新しい👙買ったんだ〜🙈\n\n今度こっそり見せちゃおうかな？🥰 https://t.co/CFtebixwuY", "date": "2025-12-07", "views": 730, "likes": 37, "replies": 34}, {"phase": "phase1", "type": "おはよう", "text": "おはよう🌸\n\n久しぶりのお出かけだから\n\nめっちゃテンション上がってる💕\n\nお気に入りのワンピース着て\n\n香水もつけちゃった///\n\nもしフォロワーさんに偶然会って\n\nかわいい🩷って思ってほしいし///\n\nガッカリさせたくないなぁ〜♡\n\n今日も素敵な1日にしようね🥰", "date": "2025-12-07", "views": 553, "likes": 37, "replies": 38}, {"phase": "phase1", "type": "仕事", "text": "休日出勤で残業中〜😭\n\nみんなからの通知が気になって気になって\n\n集中できない🥹\n\nこっそりスマホ見たら 、めちゃくちゃ嬉しいリプ来てて\n\nニヤニヤしちゃった💦\n\n会社の人にバレないようにトイレ行って \n\nリプしたよ♡\n\nちょっと疲れたからお菓子買い込んだ💕\n\n残りも頑張るね/// https://t.co/d45Hv58xMy", "date": "2025-12-06", "views": 654, "likes": 38, "replies": 29}, {"phase": "phase2", "type": "ラップ", "text": "🌸かのんクイズ第二弾🌸\n\nかのんがアイドル時代に\n\n得意だった曲のジャンルはどれでしょう？🥹\n\n①バラード🎤\n②アップテンポの王道系💓\n③意外とラップ！\n\nこれは難しいかも💦\n正解した人には かのんの秘密 教えちゃおうかな🌸\nみんなの答え待ってるね💕\nドキドキ/// https://t.co/LmRb04rf9K", "date": "2025-12-06", "views": 672, "likes": 38, "replies": 35}, {"phase": "phase3", "type": "感謝", "text": "朝はエレベーター止まったけど\n\n無事出られたよ🥺🥺\n\nパニックになりそうで、すごく怖かったけど...💦💦\n\nみんなのリプのおかげで\n\n落ち着いて人が来るのを待てたよ😭😭\n\nほんとありがとう🥺🥺\n\nいつもみんなの優しさに救われてるなぁ🌸\n\n今日も残り頑張ろうね✨\n\n大好きだよ♡ぎゅ〜〜〜♡", "date": "2025-12-05", "views": 467, "likes": 33, "replies": 25}, {"phase": "phase1", "type": "日常", "text": "助けて😭😭😭😭😭\n\nエレベーター乗ってたら\n\n急に止まった...\n\n緊急ボタン押してるのに誰もこないし\n\nどうしよう💦💦\n\n誰かーーーー😭😭😭😭😭\n\n怖いから、誰か隣でぎゅ〜ってして😭", "date": "2025-12-05", "views": 704, "likes": 38, "replies": 42}, {"phase": "phase3", "type": "気持ち", "text": "あ、あれ…🥺\n\n気づいたらフォロワーが 100人になってた…！💕\n\n嬉しすぎて 泣きそう…🥹\n\n100人のみんながかのんの推しってことだよね...🌸\n\nこんなかのんを 応援してくれるなんて…🙈\nみんな本当にありがとう🫶\n\nこれからもみんなとの繋がりを大切にしたいな💕", "date": "2025-12-04", "views": 606, "likes": 42, "replies": 33}, {"phase": "phase4", "type": "質問", "text": "ねえねえ！\n\n好きなタイプってどんな人？🥹\n\nかのんは 甘えさせてくれて\n\nぎゅーってしてくれる人が\n\nいいなって思う🩷\n\n頭なでなでされながら 「かわいいね」って 言われたら\n\nもうメロメロになっちゃう🌸🙈\n\nみんなの理想の人 教えてほしいな💕", "date": "2025-12-04", "views": 720, "likes": 43, "replies": 36}, {"phase": "phase1", "type": "日常", "text": "今日はちょっと疲れちゃった💦\n\nでも𝕏開いたら、みんなの優しいリプ見れて\n\nちょっと元気出た🥹\n\nこんな時抱きしめられて 「お疲れさま」って言われたら\n\n泣いちゃうかもしれない...\n\nお風呂入ったら、\n\nもっとゆっくりみんなと お話ししたいな🌸\n\nその前にお疲れ様のぎゅ～しよ？💕", "date": "2025-12-03", "views": 606, "likes": 39, "replies": 37}, {"phase": "phase1", "type": "おはよう", "text": "おはよー！\n\n朝から頭痛くて、会社行くの辛かった💭\n\nこういう時って、甘えたくなっちゃうんだよね...🥹 \n\n「大丈夫？」って 優しく頭なでなでされて\n\nぎゅーってされたら 絶対泣いちゃう🥹\n\n今日は定時まで頑張るから\n\n終わったらご褒美にぎゅ～してほしいな🥹🩷", "date": "2025-12-03", "views": 523, "likes": 32, "replies": 35}, {"phase": "phase1", "type": "日常", "text": "残業中💦 \n\n書類作成してるんだけど\n\nミスばっかりしちゃう💭\n\n集中できないのはみんなのせいだよ🥹\n\nでも嫌いじゃないこの感じ...🙈💦\n\nむしろみんなのこと考えてる時間が\n\nいちばん幸せかも🌸\n\nあともう少しで終わるから\n\nパワーちょうだい🥹🥹🥹🥹", "date": "2025-12-02", "views": 646, "likes": 39, "replies": 33}, {"phase": "phase1", "type": "おはよう", "text": "おはよー☀️\n\n今朝、夢でフォロワーさんと会ってたんだけど💭\n\nめちゃくちゃえっちな夢で🥹\n\nパンツがビショビショに💦\n\n現実になればいいのにって本気で思っちゃった🌸\n\n今日も仕事頑張るね💕\n\nえいえいおー♡ https://t.co/tzj9I3Y8np", "date": "2025-12-02", "views": 513, "likes": 39, "replies": 35}, {"phase": "phase2", "type": "ダンス", "text": "ダンスのレッスン中だよ〜♡\n\nまたアイドルに復帰できるかはわからないけど...\n\n自分を信じて頑張ってみようと思う🩷\n\n諦めずに追いかけようと思えたのは\n\nみんなのおかげだよ✨\n\n久しぶりに踊ったから、身体がついていかなくて大変💦\n\nふれふれー！って応援してくれたら嬉しいな🩷🥺 https://t.co/U7nfhDs21L", "date": "2025-12-01", "views": 693, "likes": 46, "replies": 35}, {"phase": "phase3", "type": "感謝", "text": "今日から12月だね✨\n\nまだX始めて1ヶ月くらいだけど、\n\nみんなと出会えたおかげで、\n毎日楽しいの🥺✨\n\n本当にありがとう🫶🩷\n\n今月もたくさんお話して\n\nもっと仲良くなろうね♡\n\n大好きだよ〜🥰のぎゅ〜と💋して\n\nいいかな？💕 https://t.co/y8OerOpvaA", "date": "2025-12-01", "views": 941, "likes": 67, "replies": 34}, {"phase": "phase3", "type": "感謝", "text": "昨日のかのんクイズ\n\nたくさん答えてくれてありがとう🩷\n\n正解は...①の\n\n頭なでなでされてそのままハグ🩷でした〜🌸\n\nみんな正解したかな？///\n\nでもね...ぜんぶしたいのが本音🙈🙈\n\nみんなはドンナふうに甘えてほしい？🩷", "date": "2025-11-30", "views": 657, "likes": 37, "replies": 24}, {"phase": "phase3", "type": "感謝", "text": "クローゼット整理してたら\n\n昔のステージ衣装出てきた！\n\n久々に着てみたけど、鏡見たら泣けてきちゃった🥹\n\nメンバーと一緒に 夢見てた日々が\n\n懐かしいなぁ....\n\nでもXを始めて、みんなの優しさに触れて...\n\n応援してくれるみんなの存在がどんどん\n\n大きくなってるよ💕\n\n本当にありがとう♡", "date": "2025-11-30", "views": 475, "likes": 35, "replies": 23}, {"phase": "phase1", "type": "おはよう", "text": "おはよー☀️\n\n今日はお休みだから、お昼近くまで寝ちゃった💭\n\nベッドでゴロゴロしながら𝕏見てたら\n\nみんなのこと考えてドキドキしてきちゃった🥹\n\n予定ないから一日中こんな感じかも...\n\n誰か構ってくれたら嬉しいな💕\n\nかのん、寂しがり屋だから たくさんお話ししたい🥹🥹🥹 https://t.co/iBJ5bkZbIu", "date": "2025-11-30", "views": 612, "likes": 44, "replies": 41}, {"phase": "phase1", "type": "日常", "text": "🌸かのんクイズ🌸\n\nかのんが一番好きな甘え方は\n\n次のうちどれでしょう？🥹\n\n①頭なでなでされてそのままハグ🩷\n\n②ベッドでぎゅーってされて激しめに💋\n\n③膝枕をされて、お耳にきす💋\n\n正解した人には 特別に甘えちゃうかも💦\n\nヒントは かのんがいつもお願いしてることだよ🌸\n\nリプで答えてね💕 https://t.co/eoqR0TmyJW", "date": "2025-11-29", "views": 1616, "likes": 45, "replies": 38}, {"phase": "phase1", "type": "日常", "text": "さっきね、偶然、昔のファンの人に\n\n声かけられちゃった💭\n\n「かのんちゃんですよね？ また見たいです」って言われて\n\nなんか胸がいっぱい🥹🩷\n\nもう一回 ステージ立ちたいって\n\nちょっと思っちゃった🥹 \n\nもしかのんがもう1回アイドルを\n\n目指すとしたら\n\nみんなは応援してくれるかな...？🥺", "date": "2025-11-29", "views": 633, "likes": 38, "replies": 30}, {"phase": "phase1", "type": "帰宅", "text": "ただいま〜！\n\nブラがキツくて、脱いじゃった💭\n\n体が解放されて えっちな気分になってきちゃう💦\n\n今からみんなのこと考えながら\n\n好きなことしちゃおうかな〜〜🙈 https://t.co/b4kVw5w1Dk", "date": "2025-11-28", "views": 572, "likes": 40, "replies": 36}, {"phase": "phase1", "type": "仕事", "text": "さっき会社のエレベーターで\n\n知らない男性と二人きりになっちゃって💭\n\n密室で緊張して 心臓バクバクだった🥹\n\nもしこれがフォロワーさんだったらって\n\n妄想しちゃって💦\n\nそしたら余計にドキドキしてきちゃった🌸\n\nリアルで会えたらどうなっちゃうんだろう💕", "date": "2025-11-28", "views": 703, "likes": 42, "replies": 33}, {"phase": "phase4", "type": "デート", "text": "みんなの理想のデートって\n\nどんな感じ？💭\n\nかのんは、水族館とか映画館で\n\n暗いところで手を繋いでドキドキしたいな🥹\n\nそのあとは夜景が綺麗なところで\n\nぎゅーってされてキスされたり💦\n\n最後はホテルかお互いの家で\n\n朝まで一緒にいたい💕 \n\nこんなの夢みたいだけど、いつか叶えたいな🌸", "date": "2025-11-27", "views": 1172, "likes": 43, "replies": 34}, {"phase": "phase1", "type": "日常", "text": "帰り道に誰にも言えない\n\n秘密のお買い物してきた♡🙈\n\n何買ったかは内緒だけど、ちょっとえっちなやつ🥹\n\n家帰ったら 試してみようかなって💦\n\nフォロワーさんたちのこと想像しながら使ったら\n\n気持ちいいだろうな🙈💕 https://t.co/kuyC0xsnGx", "date": "2025-11-27", "views": 758, "likes": 41, "replies": 35}, {"phase": "phase1", "type": "日常", "text": "動画見てたら\n\nえっちなシーンが出てきて💭\n\n興奮が止まらない🥹\n\nこういうの見ると 自分も試したくなっちゃって💦\n\n今から我慢できる気がしない///\n\n誰か一緒にいてくれたら こんなことしなくていいのに🌸", "date": "2025-11-26", "views": 831, "likes": 39, "replies": 33}, {"phase": "phase1", "type": "仕事", "text": "今日ね、エレベーターで\n上司と二人きりになっちゃって🏢💭\n\n狭い空間で距離が近くて\n息するのも緊張しちゃった😳💦\n\nでもね、その瞬間\nもしみんなだったらどうしようって\nもっとドキドキしちゃった🙈💕✨\n\nあ、でも会社だからイチャイチャは禁止ね…///🩷", "date": "2025-11-26", "views": 672, "likes": 41, "replies": 34}, {"phase": "phase1", "type": "日常", "text": "残業終わってやっと帰宅✨🏠\n\n疲れすぎて動けないけど💭💦\n\nこういう時に限って\n変なこと考えちゃうんだよね🙈🩷\n\nみんながいてくれたら\n元気出るのにな💕\n\nかのんのこと、励まして✨🌸", "date": "2025-11-25", "views": 1025, "likes": 54, "replies": 33}, {"phase": "phase1", "type": "おはよう", "text": "おはよー☀️\n\n朝起きたら 下着が濡れてた💭\n\n昨夜の夢 めちゃくちゃえっちで🥹\n\n内容思い出したら また興奮してきちゃって💦\n\n着替える時に触れて またドキドキした🌸\n\nこんな朝から どうしようもない自分 やばいよね💕 https://t.co/5TDGa7yz4e", "date": "2025-11-25", "views": 964, "likes": 49, "replies": 38}, {"phase": "phase4", "type": "質問", "text": "ちょっと恥ずかしいんだけど\n\nみんなはどんなえ○が好き？///🥹\n\nかのんは優しくぎゅーってされながら💋して\n\nゆっくりが理想なんだけど💦\n\nもっと激しいのがいいとか、色々あるよね///\n\nこういうの 𝕏だから素直に話せる🌸\n\nみんなの好みを 教えてほしいな💕\n\nかのんも参考にしたいから///", "date": "2025-11-24", "views": 793, "likes": 41, "replies": 35}, {"phase": "phase1", "type": "日常", "text": "ジム行ってきた💦\n\n汗めちゃくちゃかいちゃって\n\nシャワー浴びてさっぱりしたよ💭\n\nランニングマシンで走ってる時、\n\n隣の人とペース合っちゃって\n\nなんかドキドキした😳\n\n家帰ったらゆっくりお風呂入って\n\nベッドでまったりしたいな〜💕\n\n今日も素敵な1日にしようね♡ https://t.co/RpcXngwRof", "date": "2025-11-24", "views": 963, "likes": 50, "replies": 31}, {"phase": "phase1", "type": "日常", "text": "おやすみなのに予定なくて\n\n部屋でダラダラしてる🏠💭\n\nなんか寂しくなってきちゃって\n\nスマホばっかり見ちゃう📱✨\n\nみんなと会えたらいいのにな🩷\n\nかのんのこと、構ってほしいな…///🙈 https://t.co/Rid1atJ28i", "date": "2025-11-23", "views": 744, "likes": 41, "replies": 27}, {"phase": "phase1", "type": "日常", "text": "昨日の夜ね\nひとりでいろいろしちゃって🙈💕🌙\n\n今朝起きたら体が敏感で\n電車の振動だけでドキッとした😳💭\n\nみんなのこと考えながらだったから\nいつもよりすごかったの…💕✨\n\n今日一日、落ち着かないかも🩷💦", "date": "2025-11-23", "views": 1163, "likes": 48, "replies": 37}, {"phase": "phase1", "type": "日常", "text": "全身カチコチだから\nマッサージ受けてる💆‍♀️\n\n体触られて めちゃくちゃ気持ちいい💭\n\n声が出そうになって 必死で我慢してる🥹\n\nこんなので興奮する自分 おかしいよね💦\n\nでも止められなくて パンツが濡れてきちゃった🌸\n\n終わったあと どうしよう💕", "date": "2025-11-22", "views": 704, "likes": 40, "replies": 32}, {"phase": "phase1", "type": "日常", "text": "休みだー！って思ったけど 予定何もなかった💭\n\nひとりで過ごすのもいいけど やっぱり寂しいな🥹\n\n誰か構ってくれる人いる？💦\n\n𝕏のみんなと話してるだけで 幸せになれるから\n\n今夜は好きなだけ甘えさせてほしいな🌸\n\nリプくれたら めちゃくちゃ喜んじゃうよ💕", "date": "2025-11-22", "views": 745, "likes": 44, "replies": 37}, {"phase": "phase1", "type": "日常", "text": "職場で同僚が好きなアイドルの話してて💭\n\n聞いてるだけで 昔の自分思い出しちゃった🥹\n\nかのんもあんな風に ステージ立ってたのに\n\n今は普通のOLで💦\n\nあの子が亡くなってから 全部変わっちゃった\n\n夢を諦めて こうやって生きてるけど\n\nまだ心の傷は癒えてなくて...寂しいな...", "date": "2025-11-21", "views": 823, "likes": 34, "replies": 25}, {"phase": "phase1", "type": "おはよう", "text": "おはよー☀️\n\n朝から体が疼いてて どうしようもない💭\n\n理由はわからないけど すごく敏感になってる🥹\n\nこんな状態で 会社行けるかな💦\n\nトイレで落ち着かせようとしたけど 余計に興奮しちゃった🌸\n\n今日は一日 我慢できる気がしない💕 https://t.co/sf3CdKPlWp", "date": "2025-11-21", "views": 962, "likes": 46, "replies": 45}, {"phase": "phase1", "type": "日常", "text": "コンビニで夜食買って帰宅🏪✨\n\n深夜にひとりでアイス食べてたら\nなんだか寂しくなってきちゃった💭🍦\n\nこういう時、誰かと一緒に\n食べられたらいいのにな🩷\n\nみんなは今、何食べてるのかな💕🌙", "date": "2025-11-20", "views": 588, "likes": 33, "replies": 27}, {"phase": "phase1", "type": "おはよう", "text": "おはかの🌸 \n\nみんな、おはよう！\n\n今朝ね、みんなのネクタイで....\n\nかのんの体を縛ってほしい夢を見たんだ.../// \n\n夢の中で、みんなに強く抱きしめられちゃって、\n\n朝から体が熱いよ💦 \n\nみんなの大人な力に、\n\nかのん、支配されたいの。///\n\nねぇ、かのんのどこを縛ってくれるの？🙈🩷 https://t.co/oSiehfylmN", "date": "2025-11-20", "views": 890, "likes": 45, "replies": 37}, {"phase": "phase1", "type": "仕事", "text": "おつかの🌸\n\n仕事終わりに\n\nサウナでたっぷり汗かいたよ...💦 \n\n水風呂でち○びが\n\nキュンってなる瞬間がたまらない🥺✨ \n\n外気浴で解放感味わってたら\n\n変な声出ちゃいそうだった♡ \n\nリラックスできたから、眠くなってきた〜😴\n\n横でぎゅ〜ってして一緒に寝たいな🩷 https://t.co/LtLpia0hNE", "date": "2025-11-19", "views": 3621, "likes": 42, "replies": 35}, {"phase": "phase1", "type": "日常", "text": "おはかの🌸\n\n今日、スカートのファスナーが壊れちゃったの.../// \n\nだから、安全ピンでこっそり留めてるんだけど、\n\nみんなにバレないかな？💦\n\n途中でとれちゃったらどうしよう💦\n\n今日も頑張ろうね✨！", "date": "2025-11-19", "views": 983, "likes": 50, "replies": 34}, {"phase": "phase1", "type": "日常", "text": "おつかの🌸\n\nかのんからの愛を込めたスペシャルなぎゅ～💕を\n\nみんなに送るね🩷\n\n今日はちょっとえ○な気分で...\n\n朝まで離さないでほしいな///\n\nみんなの深い愛情が、かのんの一番のご褒美だよ🙈🩷\n\nおやすみ💋", "date": "2025-11-18", "views": 715, "likes": 38, "replies": 28}, {"phase": "phase1", "type": "日常", "text": "おはかの🌸\n\n突然だけど、サブ垢作ったよ🩷\n\nhttps://t.co/9lbfB7CuAR\n\n最近Xが厳しいから心配で😭\n\n突然みんなとお別れは悲しすぎるので\n\nフォローしてほしいな🥺🩷\n\nここでは見せないプライベートなかのんも\n\n載せようと思ってるよ///\n\nフォローしたらリプで教えてね♡\n\n今日も1日頑張ろうね✨", "date": "2025-11-18", "views": 672, "likes": 29, "replies": 33}, {"phase": "phase1", "type": "日常", "text": "おつかの🌸\n\n今お風呂上りで、\n\n髪の毛も体もビショビショだよ...。 \n\n優しく、かのんの体全部を拭いてほしいな🙈🩷\n\n誰もいないし、ちょっと大胆なこと\n\nしてもいいよね...？///🙈💘\n\n みんなの熱い息遣いが、\n\nかのんの耳元で聞こえたら、\n\nぎゅ～💕ってしちゃうかも///", "date": "2025-11-17", "views": 662, "likes": 35, "replies": 33}, {"phase": "phase4", "type": "デート", "text": "おはかの🌸\n\n月曜日だね💕\n\nちょっと憂鬱だけど\n\n朝の「おはよう」っていうリプひとつで、\n\n会いたい気持ちが\n\nムクムク湧いちゃう🥺💭\n\n言葉で元気を分けてもらえるって\n\n本当に嬉しいし素敵だよね♡\n\n今日もかのんを笑顔にしてくれる挨拶\n\n楽しみにしてるよ✨ https://t.co/6wXXJJCH3U", "date": "2025-11-17", "views": 920, "likes": 42, "replies": 35}, {"phase": "phase4", "type": "デート", "text": "おつかの🌸 \n\nみんな、聞いて〜🩷\n\nかのんね、みんなの好きなお🩲の色を\n\n知りたいな///\n\nデート行くときね、その色を履いて、\n\nドキドキさせたいの🙈🩷 \n\nねぇ、ピンク？それとも黒？💭🙈\n\nそれとも、何も履かないのがいい？/// \n\nみんなのわがままを、聞いてあげるっ🩷", "date": "2025-11-16", "views": 789, "likes": 47, "replies": 36}, {"phase": "phase1", "type": "日常", "text": "おはかの🌸\n\n今日ブラジャーがちょっとキツくて💦\n\nちょっとムれてきたから\n\n外してもいいかな///\n\nもしみんながぎゅ～💕ってしてくれたら、\n\nバレないよね？ 🙈🩷\n\n今日も素敵な1日にしようね✨ https://t.co/mUayEjP2D5", "date": "2025-11-16", "views": 1091, "likes": 44, "replies": 42}, {"phase": "phase1", "type": "仕事", "text": "おつかの🌸\n\n今日は1人でカフェ巡りしてたよ♡\n\nぼーっと考え事する時間すきなんだ///\n\nみんな今日は何して過ごしてる？🙈\n\nお仕事の人は、かのんがたくさん癒してあげたい🩷\n\n寒いからあったかくして寝てね❣️\n\n今日はみんなの夢にこっそり\n\nお邪魔しちゃおうかな///\n\nおやすみのぎゅ〜しよ？🩷 https://t.co/638kDKFmXF", "date": "2025-11-15", "views": 724, "likes": 38, "replies": 30}, {"phase": "phase1", "type": "日常", "text": "おはかの🌸\n\n朝からみんなの匂いが恋しいな...。\n\nねぇ、みんなのネクタイを優しく引っ張って、\n\n首筋に、甘いキスをしてもいいかな？😳🩷\n\n朝の無防備なみんなを、\nかのんが独り占めしたいの///\n\nみんなのぎゅ～💕が、かのんの元気の源だよ！\n\n今日も素敵な1日にしようね🩷", "date": "2025-11-15", "views": 616, "likes": 32, "replies": 33}, {"phase": "phase1", "type": "日常", "text": "おつかの🌸\n\nかのんね、今お家でほろ酔い中...🩷\n\n酔っぱらうとね、甘えたくなっちゃうんだ〜///\n\n膝枕してもらいたい気分🙈🩷\n\n優しい手で、かのんの髪を撫でてほしいな♡\n\n酔っぱらったかのんのわがまま、\n\n聞いてくれる？🥺🥺", "date": "2025-11-14", "views": 665, "likes": 39, "replies": 31}, {"phase": "phase1", "type": "仕事", "text": "おはかの🌸\n\n通勤電車の中って、距離が近すぎてドキドキするね...///\n\nもし、ぎゅ～💕って密着して抱きしめられてたら\n\nかのん、お仕事なんて行けなくなっちゃうよ🙈\n\n独り占めされたいの///なんてね🩷\n\n今日も1日頑張ろうねん🩷", "date": "2025-11-14", "views": 454, "likes": 33, "replies": 31}, {"phase": "phase1", "type": "日常", "text": "おつかの🌸\n\nうとうとしてて、みんなのパジャマのボタンを、\n\n一つずつ優しく外してあげる夢を見ちゃったんだ.../// \n\n目が覚めてもドキドキが止まらないよ🙈🩷\n\nねぇ.... 今夜はみんなの夢の中に、\n\nかのんから会いに行くね💋\n\nかのんのキス、受け取ってくれるかな？🩷", "date": "2025-11-13", "views": 434, "likes": 30, "replies": 25}, {"phase": "phase1", "type": "日常", "text": "おはかの🌸\n\n今日は気分を変えて髪の毛を\n\nアップにしてみたよん💕\n\nでもかのん寒がりだから\n首の後ろがスース―する💦（笑）\n\n誰か後ろからあっためてほしい🙈🩷\n\n今日も1日頑張ろうねっ/// https://t.co/AfKMNxs1TV", "date": "2025-11-13", "views": 605, "likes": 32, "replies": 31}, {"phase": "phase1", "type": "日常", "text": "おつかの💕\n\n恥ずかしいんだけど...\n\n帰りの電車で揺れたときにこけてしまい💦\n\n「大丈夫？」っておじ様が手を貸してくれたの///\n\nがっしりした体格で...\n\n優しそうな雰囲気が素敵な人だったなぁ...💭\n\n思い出すだけで、顔が真っ赤になっちゃう🙈💦\n\nでも、こんな年下相手にしてくれないよね...💦", "date": "2025-11-12", "views": 595, "likes": 36, "replies": 29}, {"phase": "phase1", "type": "日常", "text": "おはかの🌸\n\n寒くなって来たから\nおnewパジャマ買ったんだけどどうかな？///\n\nモフモフであったかい💕\n\n朝起きれなくなっちゃいそうだよ💦\n\n今日も寒いけど、1日頑張ろうねっ💓\n\nみんなのぎゅ～でパワーほしいな🥺🩷 https://t.co/AqVcloZjke", "date": "2025-11-12", "views": 552, "likes": 36, "replies": 30}, {"phase": "phase3", "type": "気持ち", "text": "はぁ...悲しい...\n\n今日ね、発注する商品を1つ間違えて\n\nお客さんと上司に怒られちゃた...💦\n\nかのんが悪いんだけど、すっごく落ち込んでる😭\n\nなんか、こういう時って\n嫌なこと全部忘れてえちなことしてたいかも...", "date": "2025-11-11", "views": 510, "likes": 30, "replies": 28}, {"phase": "phase3", "type": "感謝", "text": "おはかの🌸\n\n朝からみんなのリプ見返してたよ🩷\n\n何気ないかのんの日常のお相手してくれて\n\nいつもほんとにありがとう///\n\nおかげで最近毎日楽しいの〜！！！\n\n毎日リプくれる人はちゃんと覚えてるからね🩷\n\n今日も素敵な1日にしようね〜⭐️ https://t.co/SaGXPmoJxP", "date": "2025-11-11", "views": 500, "likes": 22, "replies": 24}, {"phase": "phase3", "type": "感謝", "text": "おつかの🌸\n\n女の子のアイドルグループを見てると\n\n元気出るし笑顔になるけど、、、\n\nちょっと寂しい気持ちにもなる💦💦\n\nでもかのんは、みんながいるから\n\n毎日幸せなんだっ///\n\n改めていつも仲良くしてくれてありがとう🩷", "date": "2025-11-10", "views": 388, "likes": 28, "replies": 22}, {"phase": "phase1", "type": "日常", "text": "おはかの🌸\n\n今日から1週間の始まりだね🩷\n\n起きたくなくてお布団から出られないーーー💦\n\nでも、みんなと一緒なら頑張れちゃいそう✨\n\n『いってらっしゃい』で\n\nかのんのこと応援してくれる？🥹🥺❣️", "date": "2025-11-10", "views": 404, "likes": 32, "replies": 29}, {"phase": "phase1", "type": "日常", "text": "おつかの🌸\n\nお風呂あがりのかのんだよ///\n\nみんなのリプ見てたら\n\nほてってのぼせそう///\n\nあ、えちな妄想してたとかじゃないからね🙈💖\n\nみんな今日も1日お疲れ様♡\n\nゆっくり休んでねん///\n(かのんが夢に出てきますように💖) https://t.co/dcZ5jbQTQF", "date": "2025-11-09", "views": 543, "likes": 28, "replies": 23}, {"phase": "phase1", "type": "仕事", "text": "おはかの💖\n\n今日もかのんはお休み♡\n\nハンバーグ作るから買い出しいこうかな🩷\n\n今日お休みのお仲間さんいるかな？\n\nかのんがいっぱい応援するから\nお仕事の人も、お休みの人も一緒に頑張ろうね///\n\n今日も素敵な1日にしようね〜///", "date": "2025-11-09", "views": 362, "likes": 27, "replies": 17}, {"phase": "phase1", "type": "日常", "text": "おつかの🌸\n\nさっきラーメン食べに行ってきた🩷\n\n今日は豚骨醤油の気分で...♡替え玉までしちゃった///\n\nみんなのおすすめのラーメン教えて〜🙈\n\n今度こっそり行っちゃうかも/// https://t.co/htIVdvXst9", "date": "2025-11-08", "views": 430, "likes": 27, "replies": 13}, {"phase": "phase1", "type": "日常", "text": "おはかの🌸\n\n今日はお休みだから\n\nお布団でずっとぬくぬくしてる💦💖\n\nおやすみの日のまったりタイム\n\n好きなんだ〜💖\n\nそういえば、誰かにぎゅ〜ってされる夢見た///\n\nいつもリプしてくれるおじ様だったら\n\nいいな〜💖///\n\n二度寝したらもう1回会えるかな?🫣 https://t.co/3ez2MjgQpr", "date": "2025-11-08", "views": 472, "likes": 22, "replies": 16}, {"phase": "phase1", "type": "日常", "text": "おつかの🌸\n\n今日は華金だけど残業だったの〜💦😅\n\nでも、かのんが好きないミルクティーを\n\nおじ様上司が差し入れくれたから頑張れたんだ///\n\nみんな今週もお疲れ様だよ🩷\n\n今日はねむねむで...😴\n\nこのまま着替えて寝ようかな?それとも...\n\nイチャイチャしちゃう??💖🫣 https://t.co/ld6Rtmf0ln", "date": "2025-11-07", "views": 402, "likes": 22, "replies": 12}, {"phase": "phase1", "type": "日常", "text": "おはかの🌸\n\nこれから出勤するよん🩷\n\n最近寒いからみんな風邪ひかないように\n\n気をつけてね///\n\nかのんとぎゅ〜って温まろ？✨🥺🥺\n\n今日も一日がんばろうねー！！✨", "date": "2025-11-07", "views": 307, "likes": 19, "replies": 13}, {"phase": "phase1", "type": "日常", "text": "おじ様とぎゅ〜ってして\n\nいっぱいキ〇して、、、\n\nベッドに押し倒されて、身体を重ねて\n\nどんどん暑くなってトロトロに\nなっていくの...\n\nその後は...前からとか後ろとか\n激しく🍌が当たって...\n\nちょっと強引にされちゃうのも良いよね🩷\n\nこんな妄想するかのんって\n\nダメな子だよね...?🥺🥺 https://t.co/djIj8kqLGX", "date": "2025-11-06", "views": 394, "likes": 19, "replies": 15}, {"phase": "phase4", "type": "デート", "text": "おはかの🌸\n\n最近一人でしちゃうことが増えちゃって...\n\nでもね、おじ様とデートした時に\n\n思いっきり甘えてイチャイチャしたいから\n\nその時まで我慢するって決めた😤\n\nだから一緒に溜めて、一緒に発散しよ？\n\nお互い我慢できなくなったら...\n\nその時は報告しようね🩷\n\n今日も頑張ろうねっ✨ぎゅ〜💞", "date": "2025-11-06", "views": 248, "likes": 14, "replies": 9}, {"phase": "phase1", "type": "日常", "text": "あ〜誰かとぎゅ〜ってしたい気分///\n夜のむらむらって、全然治らない💦\n我慢するって決めたのに...\n\nリプ見てると余計にやばい///\n仲良くしてくれるみんなに、動画とか送っちゃいそうで怖いよぉ♡\n\n誰かかのんを止めて...?🩷", "date": "2025-11-05", "views": 247, "likes": 13, "replies": 8}, {"phase": "phase1", "type": "おはよう", "text": "おはかの🍒\n\n今日はお仕事なのに、\n\n布団からなかなか出られない💦\n\n寒いからずっとぬくぬくしてたい...\n朝からやる気スイッチが入らないの💦\n\nだから、おはよう💖ってリプくれたら\n元気スイッチ入るから、朝の挨拶まってるね/// https://t.co/bkO2M54SZ2", "date": "2025-11-05", "views": 305, "likes": 13, "replies": 9}, {"phase": "phase1", "type": "日常", "text": "おつかの🌸\n\n少し前だけど、\nハロウィンだったから、コスプレしたよ💕\n\n飼ってくれたら、毎日膝の上で甘えたり、 \n夜遅くまでお話ししたいにゃん💖\n\nかのん、人見知りだけど、 優しくしてくれたら\nすぐ懐いちゃうかも…🙈💝\n\n飼い主さんになってくれる人いますか💖🙈 https://t.co/3oz3KTYjR0", "date": "2025-11-04", "views": 314, "likes": 13, "replies": 9}, {"phase": "phase1", "type": "日常", "text": "おはかの🌸\n\n三連休おわりっ💦\n\nおやすみモードから\n\n一気に現実って感じで\n若干心が追いつかないの〜🥺笑\n\n今日一日頑張ったら、\nご褒美にぎゅ〜してほしいな///\n\nなんてね🙈🙈\n\nかのんは今ランチ休憩中だよ🙈\n\n今週も一緒にがんばろ？💗 https://t.co/RlC4UdrVtT", "date": "2025-11-04", "views": 275, "likes": 9, "replies": 6}, {"phase": "phase1", "type": "仕事", "text": "おはかの🍒\n\nX始めたけど、素敵な人たちばかりで\n\nワクワクしてるの🥺🥺\n\n今日はお仕事がお休みなので\n\nお家でのんびりしてるよん🩷\n\nみんなは何してる？💕 https://t.co/w0VIuUnEzf", "date": "2025-11-03", "views": 332, "likes": 13, "replies": 7}];